/*!40000 ALTER TABLE `add_ons` DISABLE KEYS */;
INSERT INTO `add_ons` VALUES (1,'hot-air-balloon','Hot Air Balloon Safari','In The Air','[\"In The Air\", \"Adventure\"]','+$550',550,'per person','3–4 hours','Central Serengeti (Seronera)','Year-round (weather dependent)','Up to 16 per balloon','5:30 AM pre-dawn','The Serengeti from above, at the moment the world turns gold.','[\"http://localhost:8000/storage/add-ons/Jb3cdakAphywVFZGccD5mCXd0BhBDUUQvrkpuRz1.jpg\"]','[\"There is a moment, around 300 feet above the Serengeti floor, with the balloon still climbing and the savanna spreading beneath you in every direction, when the scale of this place becomes truly comprehensible. From ground level, the Serengeti is vast but intimate: trees at eye level, animals close, horizons cut by vegetation. From above, you see what a million years of wildlife and grassland actually looks like from the perspective of the eagle.\", \"The dawn balloon safari begins in darkness. You arrive at the launch site before first light, a thorn bush field in the middle of the Serengeti, nothing visible beyond the glow of the inflation burners and the enormous silhouette of the balloon taking shape against the stars. The briefing is calm and professional. The basket carries up to 16 passengers in compartments. Then you rise. Slowly, silently, impossibly, the earth falls away and the Serengeti reveals itself.\", \"The sunrise colors the savanna in a sequence that no camera fully captures: deep indigo giving way to rose, then amber, then the blazing gold that photographers call the magic hour. Below you, wildlife is waking. Elephant families move through the grey pre-dawn light. A lion pride stirs on a kopje. The wildebeest herds are already moving. One hour in the air. Then a champagne breakfast set on tables in the bush, linen, glassware, and the Serengeti as your dining room. It is one of the finest mornings available anywhere on Earth.\"]','The earth falls away and the Serengeti reveals itself.','[\"Pre-dawn transfer from your camp to launch site (within 45 minutes)\", \"Safety briefing with licensed pilot\", \"Approximately 60 minutes in the air\", \"Champagne bush breakfast upon landing (linen, glassware, full cooked breakfast)\", \"Flight certificate from the pilot\", \"Return transfer to your camp\", \"Third-party liability insurance\"]','[\"Additional alcoholic beverages beyond champagne breakfast\", \"Private basket upgrade (+$800 for groups of 4–6)\", \"Gratuity for the balloon crew\"]','[]','[]','[]','[\"photography-upgrade\", \"private-helicopter\", \"private-bush-dinner\"]','2026-04-03 19:51:31','2026-04-08 08:19:34'),(5,'kilimanjaro-day-hike','Kilimanjaro Day Hike','Adventure','[\"Adventure\", \"On The Ground\"]','+$280',280,'per person','6–8 hours','Kilimanjaro National Park','Year-round (best Jun–Oct, Dec–Feb)','2–8 hikers','7:00 AM','Walk the lower slopes of Africa\'s highest peak, no summit commitment required.','[\"http://localhost:8000/storage/add-ons/3aEOYAEIVqigeFhADYMKkm6OtCyJOl75uOxKSTj3.jpg\"]','[\"Not everyone has 9 days for the summit. But everyone deserves to feel the mountain beneath their feet. The Kilimanjaro Day Hike takes you into the rainforest zone of Africa\'s highest peak, an ecosystem of colobus monkeys, ancient trees draped in moss, and the unmistakable sense of ascending something immense.\", \"You hike from Marangu Gate (1,860m) to Mandara Hut (2,720m) through dense montane rainforest. The trail is well-maintained and moderate in difficulty.\", \"At Mandara Hut, you rest, take in the views where the forest thins, and enjoy a packed lunch before descending. It is a profound introduction to Kilimanjaro without the physical and time commitment.\"]','Everyone deserves to feel the mountain beneath their feet.','[\"Return transfer from Moshi/Arusha to Marangu Gate\", \"Licensed Kilimanjaro guide\", \"National park entry fees\", \"Packed lunch and water\"]','[\"Hiking boots\", \"Rain gear\", \"Gratuity for guide and porter\"]','[]','[]','[]','[\"walking-safari\", \"photography-upgrade\"]','2026-04-03 19:51:31','2026-04-08 08:21:07'),(6,'maasai-cultural-village','Maasai Cultural Village Experience','Culture','[\"Culture\", \"On The Ground\"]','+$95',95,'per person','2–3 hours','Ngorongoro Highlands','Year-round','2–12 guests','Flexible (morning or afternoon)','Step inside the world of East Africa\'s most iconic people.','[\"http://localhost:8000/storage/add-ons/zagE7SfjFwmA52EX7OsBzHlzqm5qekWLzaPT7aa6.jpg\"]','[\"The Maasai are not a tourist attraction, they are a living civilization. Semi-nomadic pastoralists who have walked this land for centuries alongside the wildlife.\", \"We work with Maasai communities who manage their own cultural tourism programs and receive direct economic benefit. Entry fees go directly to the community.\", \"A visit to a Maasai village is not a performance. It is an invitation into someone\'s home. You\'ll meet elders, learn about traditional medicine, witness the famous jumping dance, and understand how this ancient culture coexists with modern Tanzania.\"]','A visit to a Maasai village is not a performance. It is an invitation into someone\'s home.','[\"Transfer to and from the village\", \"Community entry fee\", \"Guided tour with Maasai elder\", \"Traditional jumping dance demonstration\", \"Opportunity to purchase authentic beadwork\"]','[\"Photography fees (if applicable)\", \"Additional donations to the community\"]','[]','[]','[]','[\"walking-safari\", \"private-bush-dinner\"]','2026-04-03 19:51:31','2026-04-08 08:21:59'),(7,'night-game-drive','Night Game Drive','Adventure','[\"Adventure\", \"On The Ground\"]','+$120',120,'per person','2–3 hours','Tarangire, Lake Manyara, Selous','Year-round','2–6 guests','8:00 PM (after dinner)','The bush transforms after dark. Meet the hunters of the night.','[\"http://localhost:8000/storage/add-ons/Phlu0UXn3lOh1bC2yFY43aniVUXdBTtlPC1FfXth.jpg\"]','[\"When the sun sets, a completely different Africa awakens. The diurnal animals settle into sleep, and the nocturnal hunters emerge. The night game drive offers a window into this hidden world, where predators rule and the bush reveals its most secretive inhabitants.\", \"Equipped with powerful spotlights, your guide scans the darkness for the reflective eyes of leopards, hyenas, genets, and bushbabies. The experience is atmospheric, mysterious, and often yields sightings that daytime drives never see.\", \"This is not just an extension of your game drive. It\'s a different safari entirely, conducted under the African stars with the sounds of the night as your soundtrack.\"]','When the sun sets, a completely different Africa awakens.','[\"Guided night drive with spotlight\", \"Specialist night-driving vehicle\", \"Hot drinks (tea, coffee, hot chocolate)\", \"Warm blankets\"]','[\"Alcoholic beverages\", \"Gratuity for guide\"]','[]','[]','[]','[\"walking-safari\", \"private-bush-dinner\"]','2026-04-03 19:51:31','2026-04-08 08:25:19'),(9,'honeymoon-package','Honeymoon & Romance Package','Romance','[\"Romance\", \"On The Ground\"]','+$350',350,'per couple','Throughout safari','All destinations','Year-round','Couples only','Integrated into itinerary','Because the greatest adventure should be shared with the person you love.','[\"http://localhost:8000/storage/add-ons/tzlD0EQDaeE5IUHstrmhtJCQVmcuiShNAeCmSPmh.jpg\"]','[\"A honeymoon safari is integrated with privacy, intimacy, and overwhelming beauty. This package transforms your safari into a romantic journey, with special touches designed for couples celebrating love.\", \"From champagne on arrival to private dinners under the stars, every element is curated to create moments you\'ll remember forever. We understand that your honeymoon is not just a vacation—it\'s the beginning of a lifetime of shared adventures.\", \"Let us handle the details while you focus on each other and the breathtaking landscapes of Tanzania.\"]','A honeymoon measured not in thread count but in sunsets.','[\"Room upgrade (subject to availability)\", \"Private bush dinner for two\", \"Champagne on arrival\", \"Romantic turndown service with rose petals\", \"Private vehicle for game drives\"]','[\"Spa treatments\", \"Special photography sessions\"]','[]','[]','[]','[\"private-bush-dinner\", \"zanzibar-extension\"]','2026-04-03 19:51:31','2026-04-08 08:17:12');
/*!40000 ALTER TABLE `add_ons` ENABLE KEYS */;
UNLOCK TABLES;

