INSERT INTO `destinations` VALUES (11,'serengeti','Serengeti National Park','Northern Circuit','The land of endless plains and ancient migrations.','14,750 km²','WORLD HERITAGE SITE','http://localhost:8000/storage/destinations/udlu023pjSPbXiMvQLAXZDtfYbnrJtp9gHI10J4w.jpg','http://localhost:8000/storage/destinations/RzlOS80DxD5vkQlHdZalreq2cFx0p9xU7I1RL5s4.jpg','There is no place on Earth that feels quite as primordial as the Serengeti at dawn.','published','[{\"icon\": \"paw\", \"label\": \"WILDLIFE\", \"value\": \"Big Five\"}, {\"icon\": \"calendar\", \"label\": \"PEAK TIME\", \"value\": \"Jun - Oct\"}, {\"icon\": \"thermometer\", \"label\": \"AVG TEMP\", \"value\": \"25°C\"}, {\"icon\": \"map\", \"label\": \"SIZE\", \"value\": \"14K km²\"}]','[\"The Serengeti is not just a destination, it is a reckoning with the ancient. Stretching across 14,000 square kilometers of open savanna, this is the earth at its most elemental: grass and sky and the unceasing movement of life. The name itself, derived from the Maasai word \'Siringet\', means \'endless plains\', and standing here at dawn, with the acacia silhouettes against a bleeding horizon, you understand why.\",\"This is the theater of the Great Migration, the largest movement of land animals on the planet, where 1.5 million wildebeest, 500,000 zebra, and 200,000 gazelle follow ancient instincts in a continuous loop across the Serengeti-Mara ecosystem. But the Serengeti is not only about the migration. Year-round, the park hosts the densest concentration of predators in Africa: lion prides draped across granite kopjes, leopards hanging their kills in acacia forks, and cheetah mothers teaching cubs the geometry of the hunt.\",\"In the north, the Mara River crossings, where crocodiles wait in churning brown water, are among the most visceral wildlife spectacles on Earth. In the south, Ndutu\'s short-grass plains host the calving season in January and February, when tens of thousands of wildebeest calves are born within days of each other. The Serengeti does not offer you wildlife, it demands you witness it.\"]','[{\"fact\": \"The Serengeti holds one of Africa\'s largest lion populations, over 3,000 individuals.\", \"name\": \"Lion\", \"image\": \"https://images.unsplash.com/photo-1614027164847-1b28cfe1df60?w=640&q=80\", \"likelihood\": \"Very Common\"}, {\"fact\": \"Often found in the Seronera Valley, draped over the branches of large sausage trees.\", \"name\": \"Leopard\", \"image\": \"https://images.unsplash.com/photo-1575550959106-5a7defe28b56?w=640&q=80\", \"likelihood\": \"Common\"}, {\"fact\": \"The open plains provide the perfect high-speed hunting grounds for these cats.\", \"name\": \"Cheetah\", \"image\": \"https://images.unsplash.com/photo-1534149043227-d4677db02787?w=640&q=80\", \"likelihood\": \"Common\"}, {\"fact\": \"Massive herds move between the riverine forests and the open plains year-round.\", \"name\": \"Elephant\", \"image\": \"https://images.unsplash.com/photo-1557050543-4d5f4e07ef46?w=640&q=80\", \"likelihood\": \"Very Common\"}, {\"fact\": \"A small, protected population resides in the remote Moru Kopjes area.\", \"name\": \"Black Rhino\", \"image\": \"https://images.unsplash.com/photo-1598894000396-bc30e0996899?w=640&q=80\", \"likelihood\": \"Rare\"}]','[{\"abbr\": \"JAN\", \"band\": \"good\", \"icon\": \"sun\", \"price\": \"$$$\", \"crowds\": 3, \"expect\": \"Calving season begins in the south\", \"weather\": \"Dry and warm\"}, {\"abbr\": \"FEB\", \"band\": \"peak\", \"icon\": \"sun\", \"price\": \"$$$$\", \"crowds\": 4, \"expect\": \"Peak calving, thousands of births daily\", \"weather\": \"Warm and dry\"}, {\"abbr\": \"MAR\", \"band\": \"good\", \"icon\": \"rain\", \"price\": \"$$\", \"crowds\": 2, \"expect\": \"Lush green landscapes, excellent birding\", \"weather\": \"Short rains begin\"}, {\"abbr\": \"APR\", \"band\": \"low\", \"icon\": \"rain\", \"price\": \"$\", \"crowds\": 1, \"expect\": \"Quiet trails, best value photography\", \"weather\": \"Heavy rains\"}, {\"abbr\": \"MAY\", \"band\": \"low\", \"icon\": \"rain\", \"price\": \"$\", \"crowds\": 1, \"expect\": \"Vibrant colours, migration moves north\", \"weather\": \"Rains finish\"}, {\"abbr\": \"JUN\", \"band\": \"peak\", \"icon\": \"sun\", \"price\": \"$$$$\", \"crowds\": 4, \"expect\": \"Migration in the Western Corridor\", \"weather\": \"Dry season begins\"}, {\"abbr\": \"JUL\", \"band\": \"peak\", \"icon\": \"sun\", \"price\": \"$$$$\", \"crowds\": 5, \"expect\": \"Mara River crossings begin, peak drama\", \"weather\": \"Dry and cool\"}, {\"abbr\": \"AUG\", \"band\": \"peak\", \"icon\": \"sun\", \"price\": \"$$$$\", \"crowds\": 5, \"expect\": \"Intense river crossings continue\", \"weather\": \"Dry and cool\"}, {\"abbr\": \"SEP\", \"band\": \"peak\", \"icon\": \"sun\", \"price\": \"$$$$\", \"crowds\": 5, \"expect\": \"Excellent predator sightings at water\", \"weather\": \"Dry season peak\"}, {\"abbr\": \"OCT\", \"band\": \"good\", \"icon\": \"sun\", \"price\": \"$$$\", \"crowds\": 3, \"expect\": \"Final crossings, herds move south\", \"weather\": \"Warm and dry\"}, {\"abbr\": \"NOV\", \"band\": \"good\", \"icon\": \"rain\", \"price\": \"$$\", \"crowds\": 2, \"expect\": \"Herds return to the short grass plains\", \"weather\": \"Short rains\"}, {\"abbr\": \"DEC\", \"band\": \"peak\", \"icon\": \"sun\", \"price\": \"$$$$\", \"crowds\": 4, \"expect\": \"Festive safari atmosphere in central\", \"weather\": \"Holiday season\"}]','[{\"name\": \"The Great Migration\", \"dates\": \"June - October\", \"image\": \"https://images.unsplash.com/photo-1547471080-7cc2caa01a7e?w=800&q=80\", \"highlights\": [\"River crossings\", \"Dry weather\", \"High predator action\"]}, {\"name\": \"Calving Season\", \"dates\": \"January - February\", \"image\": \"https://images.unsplash.com/photo-1516426122078-c23e76319801?w=800&q=80\", \"highlights\": [\"Newborn calves\", \"Cheetah hunting action\", \"Green plains\"]}, {\"name\": \"Emerald Season\", \"dates\": \"March - May\", \"image\": \"https://images.unsplash.com/photo-1535338454528-1b5a4f159e53?w=800&q=80\", \"highlights\": [\"Lush landscapes\", \"No crowds\", \"Best photography light\"]}]','[{\"tags\": [\"Adventure\", \"Luxury\"], \"title\": \"Balloon Safari\", \"description\": \"Float over the endless plains as the sun rises, followed by a champagne breakfast.\"}, {\"tags\": [\"Wildlife\", \"Fast\"], \"title\": \"Cheetah Interaction\", \"description\": \"Observe the world\'s fastest land animal in its natural hunting grounds on the short grass plains.\"}, {\"tags\": [\"Culture\", \"Community\"], \"title\": \"Cultural Interaction\", \"description\": \"Visit a local Maasai village and learn about their deep connection with the wild.\"}]','[\"https://images.unsplash.com/photo-1516426122078-c23e76319801?w=800&q=80\", \"https://images.unsplash.com/photo-1547471080-7cc2caa01a7e?w=800&q=80\", \"https://images.unsplash.com/photo-1535338454528-1b5a4f159e53?w=800&q=80\"]','{\"visa\": \"eVisa available, apply online before arrival\", \"best_time\": \"Mid-June to October (Migration), or Jan-Feb (Calving)\", \"transport\": \"4x4 safari vehicles and light aircraft\", \"flying_time\": \"1 hour from Arusha or 2 hours from Zanzibar\"}','[\"ngorongoro\", \"tarangire\", \"zanzibar\"]','2026-04-03 19:51:45','2026-04-07 09:47:08'),(12,'ngorongoro','Ngorongoro Conservation Area','Northern Circuit','The world largest intact volcanic caldera.','8,292 km²','UNESCO WORLD HERITAGE','http://localhost:8000/storage/destinations/bGduB707Ii9fb1vHgbPV9VRNMY8x4xuIlGmFhuL2.jpg','http://localhost:8000/storage/destinations/AxftikNcIsNDnzPdbD4ScE2WZP88vL6NkLteh2yl.jpg','Descending into the crater is like stepping into a self-contained world from another geological era.','published','[{\"icon\": \"paw\", \"label\": \"WILDLIFE\", \"value\": \"Black Rhino\"}, {\"icon\": \"calendar\", \"label\": \"PEAK TIME\", \"value\": \"Year-round\"}, {\"icon\": \"thermometer\", \"label\": \"AVG TEMP\", \"value\": \"20°C\"}, {\"icon\": \"map\", \"label\": \"SIZE\", \"value\": \"8K km²\"}]','[\"Three million years ago, a volcano larger than Kilimanjaro collapsed upon itself and formed the Ngorongoro Crater, a 264 square kilometer caldera that has since become one of the most extraordinary concentrations of wildlife on Earth. The crater is not merely a landmark, it is an entire world contained within its ancient walls.\",\"Descending the steep crater wall at dawn, as mist rolls across the soda lake below and the first golden light catches the rim, is one of the great arrivals in African travel. The crater floor hosts an estimated 25,000 large animals in permanent residence, including one of Africa\'s last viable populations of black rhino, which can often be spotted grazing in the open plains near the Lerai Forest.\",\"Beyond the crater itself, the Conservation Area spans a vast range of habitats, from mountain forests and volcanic peaks to the short-grass plains that border the Serengeti. It is unique in Tanzania as a multiple land-use area where the Maasai people coexist with the wildlife, creating a cultural landscape that is as fascinating as the wildlife spectacle.\"]','[{\"fact\": \"One of the few places in East Africa where black rhino can be reliably spotted in the wild.\", \"name\": \"Black Rhino\", \"image\": \"https://images.unsplash.com/photo-1598894000396-bc30e0996899?w=640&q=80\", \"likelihood\": \"Common\"}, {\"fact\": \"The crater hosts a dense population of large-maned lions who are famously unperturbed by vehicles.\", \"name\": \"Lion\", \"image\": \"https://images.unsplash.com/photo-1614027164847-1b28cfe1df60?w=640&q=80\", \"likelihood\": \"Very Common\"}, {\"fact\": \"Dozens of hippos can be found at the Ngoitokitok spring, often seen jostling for space.\", \"name\": \"Hippo\", \"image\": \"https://images.unsplash.com/photo-1534149043227-d4677db02787?w=640&q=80\", \"likelihood\": \"Very Common\"}, {\"fact\": \"Old bull elephants with massive tusks are an iconic sight in the Lerai Forest.\", \"name\": \"Elephant\", \"image\": \"https://images.unsplash.com/photo-1557050543-4d5f4e07ef46?w=640&q=80\", \"likelihood\": \"Common\"}, {\"fact\": \"Lake Magadi often turns pink with the presence of thousands of lesser flamingos.\", \"name\": \"Flamingo\", \"image\": \"https://images.unsplash.com/photo-1598894000396-bc30e0996899?w=640&q=80\", \"likelihood\": \"Common\"}]','[{\"abbr\": \"JAN\", \"band\": \"good\", \"icon\": \"sun\", \"price\": \"$$$\", \"crowds\": 3, \"expect\": \"Excellent visibility across the floor\", \"weather\": \"Dry and clear\"}, {\"abbr\": \"FEB\", \"band\": \"good\", \"icon\": \"sun\", \"price\": \"$$$\", \"crowds\": 3, \"expect\": \"Wildlife congregates at water sources\", \"weather\": \"Warm and dry\"}, {\"abbr\": \"MAR\", \"band\": \"good\", \"icon\": \"rain\", \"price\": \"$$\", \"crowds\": 2, \"expect\": \"Dramatic clouds, great photography\", \"weather\": \"Lush greening\"}, {\"abbr\": \"APR\", \"band\": \"low\", \"icon\": \"rain\", \"price\": \"$\", \"crowds\": 1, \"expect\": \"Quiet crater, emerald green walls\", \"weather\": \"Peak rains\"}, {\"abbr\": \"MAY\", \"band\": \"low\", \"icon\": \"rain\", \"price\": \"$\", \"crowds\": 1, \"expect\": \"Ethereal atmosphere, low vehicle count\", \"weather\": \"Mist and rain\"}, {\"abbr\": \"JUN\", \"band\": \"peak\", \"icon\": \"sun\", \"price\": \"$$$$\", \"crowds\": 4, \"expect\": \"Sharp light, easy wildlife spotting\", \"weather\": \"Cool and dry\"}, {\"abbr\": \"JUL\", \"band\": \"peak\", \"icon\": \"sun\", \"price\": \"$$$$\", \"crowds\": 5, \"expect\": \"Peak season, incredible rhino luck\", \"weather\": \"Cold mornings\"}, {\"abbr\": \"AUG\", \"band\": \"peak\", \"icon\": \"sun\", \"price\": \"$$$$\", \"crowds\": 5, \"expect\": \"Dusty plains, high action at springs\", \"weather\": \"Dry and windy\"}, {\"abbr\": \"SEP\", \"band\": \"peak\", \"icon\": \"sun\", \"price\": \"$$$$\", \"crowds\": 5, \"expect\": \"Best time for predator sightings\", \"weather\": \"Clear and dry\"}, {\"abbr\": \"OCT\", \"band\": \"good\", \"icon\": \"sun\", \"price\": \"$$$\", \"crowds\": 4, \"expect\": \"Golden grass, intense blue skies\", \"weather\": \"Warming up\"}, {\"abbr\": \"NOV\", \"band\": \"good\", \"icon\": \"rain\", \"price\": \"$$\", \"crowds\": 2, \"expect\": \"Flowers blooming on the rim\", \"weather\": \"Short rains\"}, {\"abbr\": \"DEC\", \"band\": \"peak\", \"icon\": \"sun\", \"price\": \"$$$$\", \"crowds\": 4, \"expect\": \"Celebratoy vibe, busy crater descent\", \"weather\": \"Holiday peak\"}]','[{\"name\": \"The Big Five Window\", \"dates\": \"June - September\", \"image\": \"https://images.unsplash.com/photo-1621414050946-1b936a78cf58?w=800&q=80\", \"highlights\": [\"Black rhino sightings\", \"Cooler climate\", \"Best visibility\"]}, {\"name\": \"The Green Oasis\", \"dates\": \"March - May\", \"image\": \"https://images.unsplash.com/photo-1547471080-7cc2caa01a7e?w=800&q=80\", \"highlights\": [\"Lush landscapes\", \"No crowds\", \"Active birdlife\"]}, {\"name\": \"Highland Explorer\", \"dates\": \"October - February\", \"image\": \"https://images.unsplash.com/photo-1535338454528-1b5a4f159e53?w=800&q=80\", \"highlights\": [\"Emerald views\", \"Migration nearby\", \"Cultural depth\"]}]','[{\"tags\": [\"Wildlife\", \"Iconic\"], \"title\": \"Crater Floor Game Drive\", \"description\": \"A full 6-hour descent onto the floor of the caldera, exploring diverse habitats from soda lakes to acacia forests.\"}, {\"tags\": [\"Culture\", \"Insight\"], \"title\": \"Maasai Boma Visit\", \"description\": \"Interact with the local Maasai community and learn about their ancient spiritual connection to the crater and its inhabitants.\"}, {\"tags\": [\"Walking\", \"Adventure\"], \"title\": \"Empakaai Crater Hike\", \"description\": \"A guided walk to the remote Empakaai Crater, where you can hike down to the lake shore through ancient mountain forests.\"}]','[\"https://images.unsplash.com/photo-1621414050946-1b936a78cf58?w=800&q=80\", \"https://images.unsplash.com/photo-1502911661445-12c8203fdd39?w=800&q=80\", \"https://images.unsplash.com/photo-1614027164847-1b28cfe1df60?w=800&q=80\"]','{\"visa\": \"Included in standard Tanzanian eVisa\", \"best_time\": \"June to September for wildlife, March to May for views\", \"transport\": \"Closed safari vehicle for the rim and crater\", \"flying_time\": \"45m from Arusha to Lake Manyara Airstrip\"}','[\"serengeti\", \"tarangire\", \"lake-manyara\"]','2026-04-03 19:51:45','2026-04-07 09:44:09'),(13,'tarangire','Tarangire National Park','Northern Circuit','The kingdom of the ancient baobabs and giants.','2,850 km²','NORTHERN GIANTS','http://localhost:8000/storage/destinations/kFrrAtLXGhL1sMIHwdruSrmUiHj8VrOw86GnLGwo.jpg','http://localhost:8000/storage/destinations/X7zIoBvUawRC8Udgn40fu3dgrPg2p91zNYy9GUug.jpg','Watching an elephant herd move through the silhouetted baobab forest is a memory that stays forever.','published','[{\"icon\": \"paw\", \"label\": \"WILDLIFE\", \"value\": \"Elephants\"}, {\"icon\": \"calendar\", \"label\": \"PEAK TIME\", \"value\": \"Jun - Oct\"}, {\"icon\": \"thermometer\", \"label\": \"AVG TEMP\", \"value\": \"26°C\"}, {\"icon\": \"map\", \"label\": \"SIZE\", \"value\": \"2.8K km²\"}]','[\"Tarangire is where the baobab trees reign. These ancient, barrel-trunked giants, some over a thousand years old, define the visual character of the park entirely. Standing beneath them, watching a herd of elephants move like grey fog through the undergrowth, you understand why this park is called the Kingdom of the Elephant.\",\"During the dry season (June to October), the Tarangire River becomes the only water source for hundreds of kilometres, drawing extraordinary concentrations of wildlife to its banks. Elephant herds numbering in the hundreds, among the largest gatherings in Tanzania, congregate along the river alongside buffalo, zebra, wildebeest, and giraffe. The predator action follows inevitably.\",\"Tarangire is also a paradise for birders, with over 550 species of birds recorded. The various habitats, from open plains to swamps and riverine forests, provide sanctuary for everything from the massive ostrich to the tiny, vibrant Fischer\'s lovebird. It is a park of silhouettes, best experienced as the sun sets behind the iconic baobabs.\"]','[{\"fact\": \"Tarangire has one of the highest elephant densities in Africa, herds of 300+ are common in the dry season.\", \"name\": \"African Elephant\", \"image\": \"https://images.unsplash.com/photo-1549366021-9f761d450615?w=640&q=80\", \"likelihood\": \"Very Common\"}, {\"fact\": \"Often seen in the tall grass or perched on top of termite mounds used as lookouts.\", \"name\": \"Lion\", \"image\": \"https://images.unsplash.com/photo-1614027164847-1b28cfe1df60?w=640&q=80\", \"likelihood\": \"Common\"}, {\"fact\": \"The fringe-eared oryx is one of the more elusive and beautiful inhabitants of the drier sectors.\", \"name\": \"Oryx\", \"image\": \"https://images.unsplash.com/photo-1534149043227-d4677db02787?w=640&q=80\", \"likelihood\": \"Rare\"}, {\"fact\": \"The Maasai giraffe is the national animal and is found in high numbers near the river.\", \"name\": \"Giraffe\", \"image\": \"https://images.unsplash.com/photo-1557050543-4d5f4e07ef46?w=640&q=80\", \"likelihood\": \"Very Common\"}, {\"fact\": \"Masters of disguise, they are often found in the larger trees along the Tarangire River.\", \"name\": \"Leopard\", \"image\": \"https://images.unsplash.com/photo-1575550959106-5a7defe28b56?w=640&q=80\", \"likelihood\": \"Common\"}]','[{\"abbr\": \"JAN\", \"band\": \"good\", \"icon\": \"sun\", \"price\": \"$$\", \"crowds\": 2, \"expect\": \"Lush landscapes, birding peak\", \"weather\": \"Warm and green\"}, {\"abbr\": \"FEB\", \"band\": \"good\", \"icon\": \"sun\", \"price\": \"$$\", \"crowds\": 2, \"expect\": \"Good game viewing in the swamps\", \"weather\": \"Hot and dry\"}, {\"abbr\": \"MAR\", \"band\": \"good\", \"icon\": \"rain\", \"price\": \"$$\", \"crowds\": 1, \"expect\": \"Migratory birds at their peak\", \"weather\": \"Rains begin\"}, {\"abbr\": \"APR\", \"band\": \"low\", \"icon\": \"rain\", \"price\": \"$\", \"crowds\": 1, \"expect\": \"Lush but some roads may be soft\", \"weather\": \"Peak rains\"}, {\"abbr\": \"MAY\", \"band\": \"low\", \"icon\": \"rain\", \"price\": \"$\", \"crowds\": 1, \"expect\": \"Solitude and green horizons\", \"weather\": \"Quiet rains\"}, {\"abbr\": \"JUN\", \"band\": \"peak\", \"icon\": \"sun\", \"price\": \"$$$$\", \"crowds\": 4, \"expect\": \"Wildlife moving toward the river\", \"weather\": \"Dry season begins\"}, {\"abbr\": \"JUL\", \"band\": \"peak\", \"icon\": \"sun\", \"price\": \"$$$$\", \"crowds\": 5, \"expect\": \"Elephant numbers begin to swell\", \"weather\": \"Cooler air\"}, {\"abbr\": \"AUG\", \"band\": \"peak\", \"icon\": \"sun\", \"price\": \"$$$$\", \"crowds\": 5, \"expect\": \"Massive herds reaching their peak\", \"weather\": \"Dry and dusty\"}, {\"abbr\": \"SEP\", \"band\": \"peak\", \"icon\": \"sun\", \"price\": \"$$$$\", \"crowds\": 5, \"expect\": \"Intense action at the riverbanks\", \"weather\": \"Very dry\"}, {\"abbr\": \"OCT\", \"band\": \"peak\", \"icon\": \"sun\", \"price\": \"$$$$\", \"crowds\": 4, \"expect\": \"Final concentration of wildlife\", \"weather\": \"Warm and dry\"}, {\"abbr\": \"NOV\", \"band\": \"good\", \"icon\": \"rain\", \"price\": \"$$\", \"crowds\": 2, \"expect\": \"Landscape transforms overnight\", \"weather\": \"Short rains\"}, {\"abbr\": \"DEC\", \"band\": \"peak\", \"icon\": \"sun\", \"price\": \"$$$$\", \"crowds\": 3, \"expect\": \"Emerald season safari vibe\", \"weather\": \"Holiday peak\"}]','[{\"name\": \"The Elephant Gathering\", \"dates\": \"July - October\", \"image\": \"https://images.unsplash.com/photo-1549366021-9f761d450615?w=800&q=80\", \"highlights\": [\"Massive herds\", \"River tracking\", \"Best predator sightings\"]}, {\"name\": \"The Green Sanctuary\", \"dates\": \"November - February\", \"image\": \"https://images.unsplash.com/photo-1547471080-7cc2caa01a7e?w=800&q=80\", \"highlights\": [\"Emerald vistas\", \"Active birdlife\", \"Newborn animals\"]}, {\"name\": \"Birder\'s Paradise\", \"dates\": \"March - May\", \"image\": \"https://images.unsplash.com/photo-1516426122078-c23e76319801?w=800&q=80\", \"highlights\": [\"Migratory species\", \"Lush photography\", \"Total solitude\"]}]','[{\"tags\": [\"Adventure\", \"Nature\"], \"title\": \"Walking Safari\", \"description\": \"Explore the smaller details of the park on foot with an armed ranger, understanding the ecosystem beyond the vehicles.\"}, {\"tags\": [\"Wildlife\", \"Relaxation\"], \"title\": \"Tarangire River Picnic\", \"description\": \"Enjoy lunch overlooking the lifeblood of the park as elephants and zebras come to drink just metres away.\"}, {\"tags\": [\"Speciailist\", \"Birding\"], \"title\": \"Birding Expedition\", \"description\": \"A specialist-led tour focusing on the over 550 species of birds that call this diverse park home.\"}]','[\"https://images.unsplash.com/photo-1549366021-9f761d450615?w=800&q=80\", \"https://images.unsplash.com/photo-1523806781031-bc6e572886f4?w=800&q=80\", \"https://images.unsplash.com/photo-1614027164847-1b28cfe1df60?w=800&q=80\"]','{\"visa\": \"Standard Tanzanian eVisa required\", \"best_time\": \"July to October for elephants, year-round for birding\", \"transport\": \"Open or closed safari vehicles\", \"flying_time\": \"2h drive from Arusha or 30m flight\"}','[\"serengeti\", \"ngorongoro\", \"lake-manyara\"]','2026-04-03 19:51:45','2026-04-07 09:52:18'),(14,'arusha','Arusha National Park','Northern Circuit','A pocket of mountain misty peaks and diverse forests.','137 km²','MOUNTAIN SANCTUARY','http://localhost:8000/storage/destinations/yIW2RQeo2GN1oLwzX9FfMtMviMHSZT89U8bxLZR0.jpg','http://localhost:8000/storage/destinations/qppKro8fcvaYZbtsE3DdP1OJeyWOJs8u3wVOA4kG.jpg','The silent beauty of Mt. Meru reflecting in the Momella Lakes is a moment of pure serenity.','published','[{\"icon\": \"paw\", \"label\": \"WILDLIFE\", \"value\": \"Colobus Monkey\"}, {\"icon\": \"calendar\", \"label\": \"PEAK TIME\", \"value\": \"Year-round\"}, {\"icon\": \"thermometer\", \"label\": \"AVG TEMP\", \"value\": \"22°C\"}, {\"icon\": \"map\", \"label\": \"SIZE\", \"value\": \"137 km²\"}]','[\"Arusha National Park is often overshadowed by its larger neighbours, but it is one of Tanzania\'s most beautiful and diverse gems. Located just a short drive from the city, it offers a dramatic landscape that shifts from montane forest and alkaline lakes to the towering volcanic peak of Mt. Meru, Africa\'s fifth highest mountain. It is a place of shadows and mist, where the silence is only broken by the calls of birds and the rustle of the canopy.\",\"The park is famous for its population of black-and-white colobus monkeys, whose long flowing tails and acrobatic leaps through the ancient moss-draped trees are a delight to watch. Unlike the open plains of the Serengeti, Arusha NP is an intimate experience, where you can explore the Ngurdoto Crater, often called the \'Little Ngorongoro\', and the seven Momella Lakes, each with a different hue of blue or green due to their varying mineral content.\",\"For those seeking adventure, the multi-day climb of Mt. Meru provides a challenging but rewarding trek through diverse ecological zones. On clear days, the views of Mt. Kilimanjaro from the slopes of Meru are unparalleled. It is the perfect introduction to the Tanzanian wild, whether for a day trip or as the starting point for a longer northern circuit expedition.\"]','[{\"fact\": \"Famous for their spectacular white tails and their preference for high-canopy mountain forests.\", \"name\": \"Colobus Monkey\", \"image\": \"https://images.unsplash.com/photo-1555524330-9ec8058309ec?w=640&q=80\", \"likelihood\": \"Very Common\"}, {\"fact\": \"The park has an incredibly high density of Maasai giraffes, often seen grazing against the backdrop of Mt. Meru.\", \"name\": \"Giraffe\", \"image\": \"https://images.unsplash.com/photo-1557050543-4d5f4e07ef46?w=640&q=80\", \"likelihood\": \"Very Common\"}, {\"fact\": \"Thousands of flamingos gather at the Momella Lakes, creating a pink haze on the water.\", \"name\": \"Flamingo\", \"image\": \"https://images.unsplash.com/photo-1516426122078-c23e76319801?w=640&q=80\", \"likelihood\": \"Very Common\"}, {\"fact\": \"Playful and vocal inhabitants of the park\'s dense montane forests.\", \"name\": \"Blue Monkey\", \"image\": \"https://images.unsplash.com/photo-1546272989-40c92939c6c2?w=640&q=80\", \"likelihood\": \"Common\"}, {\"fact\": \"Often found grazing in the open glades and near the forest edges.\", \"name\": \"Buffalo\", \"image\": \"https://images.unsplash.com/photo-1549366021-9f761d450615?w=640&q=80\", \"likelihood\": \"Common\"}]','[{\"abbr\": \"JAN\", \"band\": \"good\", \"icon\": \"sun\", \"price\": \"$$\", \"crowds\": 2, \"expect\": \"Excellent mountain views\", \"weather\": \"Clear and cool\"}, {\"abbr\": \"FEB\", \"band\": \"good\", \"icon\": \"sun\", \"price\": \"$$\", \"crowds\": 2, \"expect\": \"Great for birding near the lakes\", \"weather\": \"Warm and dry\"}, {\"abbr\": \"MAR\", \"band\": \"good\", \"icon\": \"rain\", \"price\": \"$$\", \"crowds\": 1, \"expect\": \"Lush forests, vibrant mosses\", \"weather\": \"Mist and rain\"}, {\"abbr\": \"APR\", \"band\": \"low\", \"icon\": \"rain\", \"price\": \"$\", \"crowds\": 1, \"expect\": \"Emerald rainforest atmosphere\", \"weather\": \"Heavy rains\"}, {\"abbr\": \"MAY\", \"band\": \"low\", \"icon\": \"rain\", \"price\": \"$\", \"crowds\": 1, \"expect\": \"Quietest month, pure solitude\", \"weather\": \"Fresh and green\"}, {\"abbr\": \"JUN\", \"band\": \"good\", \"icon\": \"sun\", \"price\": \"$$\", \"crowds\": 2, \"expect\": \"Clear air, ideal for photography\", \"weather\": \"Crisp and dry\"}, {\"abbr\": \"JUL\", \"band\": \"peak\", \"icon\": \"sun\", \"price\": \"$$$\", \"crowds\": 3, \"expect\": \"Mt. Meru trekking season peak\", \"weather\": \"Cold mornings\"}, {\"abbr\": \"AUG\", \"band\": \"peak\", \"icon\": \"sun\", \"price\": \"$$$\", \"crowds\": 3, \"expect\": \"Perfect walking safari conditions\", \"weather\": \"Dry and clear\"}, {\"abbr\": \"SEP\", \"band\": \"peak\", \"icon\": \"sun\", \"price\": \"$$$\", \"crowds\": 3, \"expect\": \"Best for colobus monkey sightings\", \"weather\": \"Warm and dry\"}, {\"abbr\": \"OCT\", \"band\": \"good\", \"icon\": \"sun\", \"price\": \"$$\", \"crowds\": 2, \"expect\": \"Migratory birds begin to arrive\", \"weather\": \"Clear skies\"}, {\"abbr\": \"NOV\", \"band\": \"good\", \"icon\": \"rain\", \"price\": \"$$\", \"crowds\": 2, \"expect\": \"Flowering montane plants\", \"weather\": \"Short rains\"}, {\"abbr\": \"DEC\", \"band\": \"peak\", \"icon\": \"sun\", \"price\": \"$$$\", \"crowds\": 3, \"expect\": \"Ideal for festive day trips\", \"weather\": \"Holiday bright\"}]','[{\"name\": \"Mount Meru Climbing\", \"dates\": \"July - February\", \"image\": \"https://images.unsplash.com/photo-1504006833117-8886a355efbf?w=800&q=80\", \"highlights\": [\"Summit reaches\", \"Alpine views\", \"Diverse zones\"]}, {\"name\": \"Birding & Lakes\", \"dates\": \"November - April\", \"image\": \"https://images.unsplash.com/photo-1547471080-7cc2caa01a7e?w=800&q=80\", \"highlights\": [\"Flamingo flocks\", \"Migratory species\", \"Lush scenery\"]}, {\"name\": \"Walking Haven\", \"dates\": \"June - September\", \"image\": \"https://images.unsplash.com/photo-1535338454528-1b5a4f159e53?w=800&q=80\", \"highlights\": [\"Guided bush walks\", \"Colobus tracking\", \"Cooler climate\"]}]','[{\"tags\": [\"Water\", \"Serene\"], \"title\": \"Canoeing on Momella Lakes\", \"description\": \"A unique way to see wildlife from the water, including hippos and thousands of flamingos.\"}, {\"tags\": [\"Walking\", \"Adventure\"], \"title\": \"Arusha NP Walking Safari\", \"description\": \"Accompanied by an armed ranger, venture onto the savanna glades to see giraffes and buffalos up close.\"}, {\"tags\": [\"Views\", \"Iconic\"], \"title\": \"Ngurdoto Crater Viewpoint\", \"description\": \"Take in the spectacular panoramic views of the \\\"Little Ngorongoro\\\" from the rim of this ancient caldera.\"}]','[\"https://images.unsplash.com/photo-1504006833117-8886a355efbf?w=800&q=80\", \"https://images.unsplash.com/photo-1555061614-7225cb85834d?w=800&q=80\", \"https://images.unsplash.com/photo-1546272989-40c92939c6c2?w=800&q=80\"]','{\"visa\": \"Standard Tanzanian eVisa applies\", \"best_time\": \"June to February for views and trekking\", \"transport\": \"Accessible by standard vehicles or safari 4x4\", \"flying_time\": \"45m drive from central Arusha city\"}','[\"serengeti\", \"kilimanjaro\", \"tarangire\"]','2026-04-03 19:51:45','2026-04-07 09:31:14'),(15,'lake-manyara','Lake Manyara National Park','Northern Circuit','A gem of groundwater forest and pink flamingos.','330 km²','RIFT VALLEY GEM','http://localhost:8000/storage/destinations/ViFQXQpSkPyjxQDbRnmSwRouNP3f5OyW4MC12xqy.jpg','http://localhost:8000/storage/destinations/PbGTKBIQkjFgDQ9LRMKUiWRUinCgEX5l84ifGXmj.jpg','The sight of thousands of flamingos as a pink ribbon along the lake shore is a Manyara classic.','published','[{\"icon\": \"paw\", \"label\": \"WILDLIFE\", \"value\": \"Tree Lions\"}, {\"icon\": \"calendar\", \"label\": \"PEAK TIME\", \"value\": \"Jun - Oct\"}, {\"icon\": \"thermometer\", \"label\": \"AVG TEMP\", \"value\": \"24°C\"}, {\"icon\": \"map\", \"label\": \"SIZE\", \"value\": \"330 km²\"}]','[\"Ernest Hemingway once described Lake Manyara as the loveliest lake he had seen in Africa, and it is easy to see why. Tucked at the base of the Great Rift Valley Escarpment, the park is a surprisingly diverse mix of dense groundwater forest, open floodplains, and the vast soda lake itself. It is a compact sanctuary that punches far above its weight in terms of sheer scenic beauty.\",\"The park is most famous for its tree-climbing lions, a rare behavior that is a signature of Manyara\'s prides. As you move from the lush forest\\u2014where baboons and blue monkeys play in the ancient mahogany trees\\u2014to the acacia woodlands, you might spot these predators draped over the branches of large sausage or umbrella trees. The lake shore is equally spectacular, often shimmering pink with the presence of thousands of lesser flamingos and other migratory waterfowl.\",\"Beyond the lions and birds, Manyara is home to large herds of elephants, buffalos, and giraffes. The park\'s compact size makes it an excellent choice for a productive day trip or a gentle introduction to the northern circuit. Whether you are observing hippos at the hippo pool or taking in the views from the Maji Moto hot springs, Manyara offers a tranquil and visually stunning safari experience.\"]','[{\"fact\": \"Manyara\'s lions are world-famous for their unique habit of climbing and resting in trees.\", \"name\": \"Lion\", \"image\": \"https://images.unsplash.com/photo-1614027164847-1b28cfe1df60?w=640&q=80\", \"likelihood\": \"Common\"}, {\"fact\": \"Huge flocks of lesser flamingos create a vibrant pink fringe along the lake edge.\", \"name\": \"Flamingo\", \"image\": \"https://images.unsplash.com/photo-1516426122078-c23e76319801?w=640&q=80\", \"likelihood\": \"Very Common\"}, {\"fact\": \"The park supports a healthy population of elephants that move frequently between the forest and the lake.\", \"name\": \"Elephant\", \"image\": \"https://images.unsplash.com/photo-1557050543-4d5f4e07ef46?w=640&q=80\", \"likelihood\": \"Very Common\"}, {\"fact\": \"Manyara is home to some of the largest baboon troops seen in Africa.\", \"name\": \"Baboon\", \"image\": \"https://images.unsplash.com/photo-1546272989-40c92939c6c2?w=640&q=80\", \"likelihood\": \"Very Common\"}, {\"fact\": \"The hippo pool at the northern tip of the lake provides reliable and close-up sightings.\", \"name\": \"Hippo\", \"image\": \"https://images.unsplash.com/photo-1534149043227-d4677db02787?w=640&q=80\", \"likelihood\": \"Common\"}]','[{\"abbr\": \"JAN\", \"band\": \"good\", \"icon\": \"sun\", \"price\": \"$$\", \"crowds\": 2, \"expect\": \"Excellent birding on the lake\", \"weather\": \"Dry and warm\"}, {\"abbr\": \"FEB\", \"band\": \"good\", \"icon\": \"sun\", \"price\": \"$$\", \"crowds\": 2, \"expect\": \"Lions active in the tree shade\", \"weather\": \"Hot and dry\"}, {\"abbr\": \"MAR\", \"band\": \"good\", \"icon\": \"rain\", \"price\": \"$$\", \"crowds\": 1, \"expect\": \"Lush green groundwater forest\", \"weather\": \"Short rains\"}, {\"abbr\": \"APR\", \"band\": \"low\", \"icon\": \"rain\", \"price\": \"$\", \"crowds\": 1, \"expect\": \"Emerald vistas, quietest trails\", \"weather\": \"Heavy rains\"}, {\"abbr\": \"MAY\", \"band\": \"low\", \"icon\": \"rain\", \"price\": \"$\", \"crowds\": 1, \"expect\": \"Ethereal light for photography\", \"weather\": \"Mist and rain\"}, {\"abbr\": \"JUN\", \"band\": \"good\", \"icon\": \"sun\", \"price\": \"$$$\", \"crowds\": 3, \"expect\": \"Wildlife moving toward water\", \"weather\": \"Crisp and dry\"}, {\"abbr\": \"JUL\", \"band\": \"peak\", \"icon\": \"sun\", \"price\": \"$$$$\", \"crowds\": 4, \"expect\": \"Peak season for game viewing\", \"weather\": \"Cool and dry\"}, {\"abbr\": \"AUG\", \"band\": \"peak\", \"icon\": \"sun\", \"price\": \"$$$$\", \"crowds\": 4, \"expect\": \"Best visibility in the woodlands\", \"weather\": \"Dry and clear\"}, {\"abbr\": \"SEP\", \"band\": \"peak\", \"icon\": \"sun\", \"price\": \"$$$$\", \"crowds\": 4, \"expect\": \"High activity at the lake shore\", \"weather\": \"Warm and dry\"}, {\"abbr\": \"OCT\", \"band\": \"good\", \"icon\": \"sun\", \"price\": \"$$$\", \"crowds\": 3, \"expect\": \"Migratory birds arrival peak\", \"weather\": \"Warm and dry\"}, {\"abbr\": \"NOV\", \"band\": \"good\", \"icon\": \"rain\", \"price\": \"$$\", \"crowds\": 2, \"expect\": \"Fresh greening of the plains\", \"weather\": \"Short rains\"}, {\"abbr\": \"DEC\", \"band\": \"peak\", \"icon\": \"sun\", \"price\": \"$$$$\", \"crowds\": 3, \"expect\": \"Excellent holiday safari vibe\", \"weather\": \"Holiday festive\"}]','[{\"name\": \"The Birding Peak\", \"dates\": \"November - June\", \"image\": \"https://images.unsplash.com/photo-1516426122078-c23e76319801?w=800&q=80\", \"highlights\": [\"Flamingo concentrations\", \"Migratory species\", \"Lush scenery\"]}, {\"name\": \"The Dry Game Season\", \"dates\": \"July - October\", \"image\": \"https://images.unsplash.com/photo-1547471080-7cc2caa01a7e?w=800&q=80\", \"highlights\": [\"Tree-climbing lions\", \"Large mammal herds\", \"Best visibility\"]}, {\"name\": \"The Secret Emerald\", \"dates\": \"April - May\", \"image\": \"https://images.unsplash.com/photo-1535338454528-1b5a4f159e53?w=800&q=80\", \"highlights\": [\"Quiet trails\", \"Lush forest walks\", \"Dramatic photography\"]}]','[{\"tags\": [\"Nature\", \"Walking\"], \"title\": \"Groundwater Forest Walk\", \"description\": \"Explore the unique lush forest at the base of the escarpment, home to massive mahogany trees and lively primate troops.\"}, {\"tags\": [\"Adventure\", \"Views\"], \"title\": \"Manyara Treetop Walkway\", \"description\": \"Walk through the canopy of the forest on a suspended walkway, getting a bird\'s eye view of the unique ecosystem.\"}, {\"tags\": [\"Wildlife\", \"Intense\"], \"title\": \"Night Game Drive\", \"description\": \"Experience the park like never before, spotting nocturnal creatures like genets and porcupines under the guidance of expert rangers.\"}]','[\"https://images.unsplash.com/photo-1516426122078-c23e76319801?w=800&q=80\", \"https://images.unsplash.com/photo-1547471080-7cc2caa01a7e?w=800&q=80\", \"https://images.unsplash.com/photo-1535338454528-1b5a4f159e53?w=800&q=80\"]','{\"visa\": \"Standard Tanzanian eVisa applies\", \"best_time\": \"July to October for lions, November to June for birding\", \"transport\": \"Standard or 4x4 safari vehicles\", \"flying_time\": \"1.5 hour drive from Arusha or 30m flight\"}','[\"serengeti\", \"ngorongoro\", \"tarangire\"]','2026-04-03 19:51:45','2026-04-07 09:39:09'),(16,'kilimanjaro','Mount Kilimanjaro National Park','Northern Circuit','The Roof of Africa standing alone in the clouds.','1,688 km²','HIGHEST ALONE','http://localhost:8000/storage/destinations/YMYi2aufvMcusmS5aAWgQHdq3FKaAo93ZipKP2XO.jpg','http://localhost:8000/storage/destinations/ASMrCD8Ynh5Lon8sHXep65J7P3tEXQvT7mQmEB24.jpg','Standing on Uhuru Peak at sunrise, with the world below hidden by a sea of clouds, is the ultimate African triumph.','published','[{\"icon\": \"paw\", \"label\": \"WILDLIFE\", \"value\": \"Alpine\"}, {\"icon\": \"calendar\", \"label\": \"PEAK TIME\", \"value\": \"Jan - Mar\"}, {\"icon\": \"thermometer\", \"label\": \"AVG TEMP\", \"value\": \"10°C\"}, {\"icon\": \"map\", \"label\": \"HEIGHT\", \"value\": \"5,895m\"}]','[\"Mount Kilimanjaro is not just a mountain, it is an icon. Rising 5,895 meters above the East African plains, it is the highest free-standing mountain in the world and the roof of the African continent. To climb it is to walk through five different ecological zones in a single journey, from tropical rainforest and alpine meadows to the haunting lunar landscape of the summit crater.\",\"The journey to Uhuru Peak is as much a mental challenge as it is a physical one. Each route\\u2014Marangu, Machame, Lemosho, and others\\u2014offers a unique perspective on the mountain\'s shifting majesty. You begin in the lush montane forest, home to elusive primates and birds, before emerging into the heather and moorland zones, where the giant groundsels stand like silent guardians against the thinning air.\",\"But Kilimanjaro is not only for climbers. The surrounding national park offers spectacular day hikes and opportunities to witness the mountain\'s raw power from its base. The sight of Kibo\'s snow-capped peak glowing orange in the first light of dawn, while the plains below are still in shadow, is an experience that stays with every visitor forever. It is Africa\'s greatest landmark, a testament to the earth\'s ancient volcanic power.\"]','[{\"fact\": \"Found in the dense montane forest zone at the base of the mountain.\", \"name\": \"Colobus Monkey\", \"image\": \"https://images.unsplash.com/photo-1555524330-9ec8058309ec?w=640&q=80\", \"likelihood\": \"Common\"}, {\"fact\": \"Frequently seen playing in the canopy near the park gates.\", \"name\": \"Blue Monkey\", \"image\": \"https://images.unsplash.com/photo-1546272989-40c92939c6c2?w=640&q=80\", \"likelihood\": \"Common\"}, {\"fact\": \"A resilient inhabitant of the higher alpine moorland zones.\", \"name\": \"Four-striped Mouse\", \"image\": \"https://images.unsplash.com/photo-1535338454528-1b5a4f159e53?w=640&q=80\", \"likelihood\": \"Very Common\"}, {\"fact\": \"Often seen feeding on the nectar of giant lobelias in the moorland zone.\", \"name\": \"Malachite Sunbird\", \"image\": \"https://images.unsplash.com/photo-1516426122078-c23e76319801?w=640&q=80\", \"likelihood\": \"Common\"}, {\"fact\": \"Occasional sightings in the lower forest zones, though they are very elusive here.\", \"name\": \"Elephant\", \"image\": \"https://images.unsplash.com/photo-1557050543-4d5f4e07ef46?w=640&q=80\", \"likelihood\": \"Rare\"}]','[{\"abbr\": \"JAN\", \"band\": \"peak\", \"icon\": \"sun\", \"price\": \"$$$$\", \"crowds\": 4, \"expect\": \"Ideal climbing conditions, best visibility\", \"weather\": \"Clear and dry\"}, {\"abbr\": \"FEB\", \"band\": \"peak\", \"icon\": \"sun\", \"price\": \"$$$$\", \"crowds\": 4, \"expect\": \"Excellent summit window\", \"weather\": \"Warm and clear\"}, {\"abbr\": \"MAR\", \"band\": \"good\", \"icon\": \"sun\", \"price\": \"$$$\", \"crowds\": 2, \"expect\": \"Good climbing before the heavy rains\", \"weather\": \"Rains begin late\"}, {\"abbr\": \"APR\", \"band\": \"low\", \"icon\": \"rain\", \"price\": \"$\", \"crowds\": 1, \"expect\": \"Not recommended for climbing\", \"weather\": \"Heavy rains\"}, {\"abbr\": \"MAY\", \"band\": \"low\", \"icon\": \"rain\", \"price\": \"$\", \"crowds\": 1, \"expect\": \"Snow on the summit, challenging\", \"weather\": \"Persistent rain\"}, {\"abbr\": \"JUN\", \"band\": \"good\", \"icon\": \"sun\", \"price\": \"$$$\", \"crowds\": 3, \"expect\": \"Clear air, ideal for photography\", \"weather\": \"Cold and dry\"}, {\"abbr\": \"JUL\", \"band\": \"peak\", \"icon\": \"sun\", \"price\": \"$$$$\", \"crowds\": 4, \"expect\": \"Busy season, clear summit days\", \"weather\": \"Very cold\"}, {\"abbr\": \"AUG\", \"band\": \"peak\", \"icon\": \"sun\", \"price\": \"$$$$\", \"crowds\": 5, \"expect\": \"Peak climbing season\", \"weather\": \"Dry and clear\"}, {\"abbr\": \"SEP\", \"band\": \"peak\", \"icon\": \"sun\", \"price\": \"$$$$\", \"crowds\": 5, \"expect\": \"Excellent all-round conditions\", \"weather\": \"Warmer air\"}, {\"abbr\": \"OCT\", \"band\": \"good\", \"icon\": \"sun\", \"price\": \"$$$\", \"crowds\": 3, \"expect\": \"Good climbing with dramatic clouds\", \"weather\": \"Cloudier skies\"}, {\"abbr\": \"NOV\", \"band\": \"good\", \"icon\": \"rain\", \"price\": \"$$\", \"crowds\": 2, \"expect\": \"Quiet mountain, lush lower slopes\", \"weather\": \"Short rains\"}, {\"abbr\": \"DEC\", \"band\": \"peak\", \"icon\": \"sun\", \"price\": \"$$$$\", \"crowds\": 4, \"expect\": \"Celebratory summit attempts\", \"weather\": \"Holiday festive\"}]','[{\"name\": \"The Main Summit Window\", \"dates\": \"January - March\", \"image\": \"https://images.unsplash.com/photo-1547471080-7cc2caa01a7e?w=800&q=80\", \"highlights\": [\"Clear skies\", \"Warmest weather\", \"Best summit luck\"]}, {\"name\": \"The Winter Challenge\", \"dates\": \"June - September\", \"image\": \"https://images.unsplash.com/photo-1535338454528-1b5a4f159e53?w=800&q=80\", \"highlights\": [\"Crisp air\", \"Amazing visibility\", \"Dynamic atmosphere\"]}, {\"name\": \"The Quiet Path\", \"dates\": \"October - December\", \"image\": \"https://images.unsplash.com/photo-1502481851512-e9e2529bbbf9?w=800&q=80\", \"highlights\": [\"Fewer climbers\", \"Lush lower slopes\", \"Dramatic vistas\"]}]','[{\"tags\": [\"Adventure\", \"Trek\"], \"title\": \"Machame Route Trek\", \"description\": \"The \\\"Whiskey\\\" route, known for its scenic beauty and challenging sections like the Barranco Wall.\"}, {\"tags\": [\"Remote\", \"Scenic\"], \"title\": \"Lemosho Route Expedition\", \"description\": \"A longer, more remote route offering superior acclimatization and breathtaking forest starts.\"}, {\"tags\": [\"Intro\", \"Nature\"], \"title\": \"Marangu Day Hike\", \"description\": \"A perfect taste of the mountain for those not seeking a full summit attempt, reaching the first camp through dense rainforest.\"}]','[\"https://images.unsplash.com/photo-1502481851512-e9e2529bbbf9?w=800&q=80\", \"https://images.unsplash.com/photo-1535338454528-1b5a4f159e53?w=800&q=80\", \"https://images.unsplash.com/photo-1547471080-7cc2caa01a7e?w=800&q=80\"]','{\"visa\": \"Standard Tanzanian eVisa applies\", \"best_time\": \"January to March and June to September\", \"transport\": \"Standard vehicles to park gates, then on foot\", \"flying_time\": \"1h drive from Kilimanjaro Airport (JRO)\"}','[\"arusha\", \"serengeti\", \"tarangire\"]','2026-04-03 19:51:45','2026-04-07 09:41:16'),(17,'ruaha','Ruaha National Park','Southern Circuit','A vast wilderness of baobabs and massive lion prides.','20,226 km²','REMOTE GIANT','http://localhost:8000/storage/destinations/JPDjt5phiLmZ5NwRe8XxA5X81Znk1sT1I08cRAJG.jpg','http://localhost:8000/storage/destinations/U6G03pKHk5NZdvlqKShwdWdOC9zj94kvEiRWVVH9.jpg','Ruaha is Africa as it was a century ago: wild, rugged, and completely uncompromising.','published','[{\"icon\": \"paw\", \"label\": \"WILDLIFE\", \"value\": \"Wild Dogs\"}, {\"icon\": \"calendar\", \"label\": \"PEAK TIME\", \"value\": \"Jun - Oct\"}, {\"icon\": \"thermometer\", \"label\": \"AVG TEMP\", \"value\": \"28°C\"}, {\"icon\": \"map\", \"label\": \"SIZE\", \"value\": \"20K km²\"}]','[\"Ruaha National Park is the largest national park in Tanzania, yet it remains one of its best-kept secrets. This is a wilderness of staggering proportions, characterized by a rugged landscape of ancient baobabs, rocky hills, and the Great Ruaha River. It is a place for the serious safari-goer, where the wildlife is wild and the human footprint is incredibly light.\",\"The park is legendary for its predator population, specifically its massive lion prides which can sometimes number over 20 individuals. It is also one of the few places in East Africa where you can see both Greater and Lesser Kudu, alongside a significant population of the endangered African wild dog. The river banks are a constant theater of life, drawing elephants, buffalos, and waterbucks in high numbers during the dry season.\",\"Because of its remote location, Ruaha offers a level of exclusivity and solitude that is hard to find in the northern parks. You can drive for hours without seeing another vehicle, allowing for an intimate connection with the landscape. Whether you are tracking leopards in the riverine forest or watching the sun set behind a thousand-year-old baobab, Ruaha delivers a raw and authentic African experience.\"]','[{\"fact\": \"Ruaha holds about 10% of the world\'s remaining lion population, with famously large prides.\", \"name\": \"Lion\", \"image\": \"https://images.unsplash.com/photo-1614027164847-1b28cfe1df60?w=640&q=80\", \"likelihood\": \"Very Common\"}, {\"fact\": \"One of the best places in Africa to search for these highly social and endangered predators.\", \"name\": \"Wild Dog\", \"image\": \"https://images.unsplash.com/photo-1575550959106-5a7defe28b56?w=640&q=80\", \"likelihood\": \"Rare\"}, {\"fact\": \"The park\'s emblem, these elegant antelopes are frequently seen in the bush lands.\", \"name\": \"Greater Kudu\", \"image\": \"https://images.unsplash.com/photo-1549366021-9f761d450615?w=640&q=80\", \"likelihood\": \"Common\"}, {\"fact\": \"Massive herds congregate along the Great Ruaha River during the dry months.\", \"name\": \"Elephant\", \"image\": \"https://images.unsplash.com/photo-1557050543-4d5f4e07ef46?w=640&q=80\", \"likelihood\": \"Very Common\"}, {\"fact\": \"Often spotted in the large trees lining the riverbanks and rocky outcrops.\", \"name\": \"Leopard\", \"image\": \"https://images.unsplash.com/photo-1575550959106-5a7defe28b56?w=640&q=80\", \"likelihood\": \"Common\"}]','[{\"abbr\": \"JAN\", \"band\": \"good\", \"icon\": \"sun\", \"price\": \"$$\", \"crowds\": 2, \"expect\": \"Lush landscapes, active birdlife\", \"weather\": \"Warm and green\"}, {\"abbr\": \"FEB\", \"band\": \"good\", \"icon\": \"sun\", \"price\": \"$$\", \"crowds\": 2, \"expect\": \"Good sightings at the river pools\", \"weather\": \"Hot and clear\"}, {\"abbr\": \"MAR\", \"band\": \"good\", \"icon\": \"rain\", \"price\": \"$$\", \"crowds\": 1, \"expect\": \"Emerald vistas, calm atmosphere\", \"weather\": \"Short rains\"}, {\"abbr\": \"APR\", \"band\": \"low\", \"icon\": \"rain\", \"price\": \"$\", \"crowds\": 1, \"expect\": \"Lush but challenging road conditions\", \"weather\": \"Heavy rains\"}, {\"abbr\": \"MAY\", \"band\": \"low\", \"icon\": \"rain\", \"price\": \"$\", \"crowds\": 1, \"expect\": \"Solitude and vibrant photography\", \"weather\": \"Quiet rains\"}, {\"abbr\": \"JUN\", \"band\": \"good\", \"icon\": \"sun\", \"price\": \"$$$\", \"crowds\": 3, \"expect\": \"Excellent game viewing begins\", \"weather\": \"Dry and crisp\"}, {\"abbr\": \"JUL\", \"band\": \"peak\", \"icon\": \"sun\", \"price\": \"$$$$\", \"crowds\": 4, \"expect\": \"Peak season for predator activity\", \"weather\": \"Cool and dry\"}, {\"abbr\": \"AUG\", \"band\": \"peak\", \"icon\": \"sun\", \"price\": \"$$$$\", \"crowds\": 4, \"expect\": \"High wildlife concentration at water\", \"weather\": \"Dry and clear\"}, {\"abbr\": \"SEP\", \"band\": \"peak\", \"icon\": \"sun\", \"price\": \"$$$$\", \"crowds\": 4, \"expect\": \"Best time for big cat sightings\", \"weather\": \"Warm and dry\"}, {\"abbr\": \"OCT\", \"band\": \"good\", \"icon\": \"sun\", \"price\": \"$$$\", \"crowds\": 3, \"expect\": \"Golden landscapes, intense blue horizons\", \"weather\": \"Warming up\"}, {\"abbr\": \"NOV\", \"band\": \"good\", \"icon\": \"rain\", \"price\": \"$$\", \"crowds\": 2, \"expect\": \"Fresh greening of the bush\", \"weather\": \"Short rains\"}, {\"abbr\": \"DEC\", \"band\": \"peak\", \"icon\": \"sun\", \"price\": \"$$$$\", \"crowds\": 3, \"expect\": \"Festive safari vibe in central\", \"weather\": \"Holiday season\"}]','[{\"name\": \"The Predator peak\", \"dates\": \"July - October\", \"image\": \"https://images.unsplash.com/photo-1547471080-7cc2caa01a7e?w=800&q=80\", \"highlights\": [\"Large lion prides\", \"Wild dog tracking\", \"River action\"]}, {\"name\": \"The Emerald Wilderness\", \"dates\": \"November - March\", \"image\": \"https://images.unsplash.com/photo-1516426122078-c23e76319801?w=800&q=80\", \"highlights\": [\"Migratory birds\", \"Lush baobabs\", \"Newborn animals\"]}, {\"name\": \"The Solitude Season\", \"dates\": \"April - May\", \"image\": \"https://images.unsplash.com/photo-1535338454528-1b5a4f159e53?w=800&q=80\", \"highlights\": [\"Total wilderness feel\", \"No other vehicles\", \"Dramatic light\"]}]','[{\"tags\": [\"Wildlife\", \"Intense\"], \"title\": \"Ruaha River Tracking\", \"description\": \"Follow the lifeblood of the park on a game drive, witnessing the intense daily drama at the water\'s edge.\"}, {\"tags\": [\"Walking\", \"Adventure\"], \"title\": \"Walking with the Giants\", \"description\": \"A guided walk among the ancient baobabs, learning about the smaller inhabitants and tracking predators on foot.\"}, {\"tags\": [\"Luxury\", \"Serene\"], \"title\": \"Bush Picnic at Sunset\", \"description\": \"Enjoy a private sundowner overlooking the vast plains as the sky turns into a canvas of oranges and purples.\"}]','[\"https://images.unsplash.com/photo-1547471080-7cc2caa01a7e?w=800&q=80\", \"https://images.unsplash.com/photo-1516426122078-c23e76319801?w=800&q=80\", \"https://images.unsplash.com/photo-1535338454528-1b5a4f159e53?w=800&q=80\"]','{\"visa\": \"Standard Tanzanian eVisa applies\", \"best_time\": \"July to October for game viewing\", \"transport\": \"Exclusively by light aircraft and 4x4 safari vehicles\", \"flying_time\": \"1.5h to 2h flight from Dar es Salaam or Arusha\"}','[\"selous\", \"mikumi\", \"serengeti\"]','2026-04-03 19:51:45','2026-04-07 09:59:41'),(18,'selous','Nyerere National Park (Selous)','Southern Circuit','A watery wilderness of rivers, lakes, and wild dogs.','30,893 km²','LARGEST RESERVE','http://localhost:8000/storage/destinations/ogO6ZbSYiSogjEkpigrietSpabD1g4Z2IzGzFkG3.jpg','http://localhost:8000/storage/destinations/0IIHkg2ukmRDVCUE0UkYs9GHYzRhGRTz0pGJepBK.jpg','Drifting silently down the Rufiji River as the sun sets is the quintessential Selous experience.','published','[{\"icon\": \"paw\", \"label\": \"WILDLIFE\", \"value\": \"Wild Dogs\"}, {\"icon\": \"calendar\", \"label\": \"PEAK TIME\", \"value\": \"Jun - Oct\"}, {\"icon\": \"thermometer\", \"label\": \"AVG TEMP\", \"value\": \"30°C\"}, {\"icon\": \"map\", \"label\": \"SIZE\", \"value\": \"30K km²\"}]','[\"Nyerere National Park, formerly known as the Selous Game Reserve, is a vast watery wilderness that offers a completely different safari experience from the northern plains. Dominated by the mighty Rufiji River and its complex system of lakes and lagoons, the park is a lush, sprawling sanctuary where the water is the lifeblood of the ecosystem.\",\"The defining feature of Nyerere is the ability to conduct boat safaris, allowing you to drift silently among pods of hippos and massive crocodiles while observing elephants and buffalos drinking at the water\'s edge. It is also one of the last great strongholds of the African wild dog, which flourish in the park\'s diverse mix of riverine forest, palm groves, and open grasslands.\",\"Because of its size and the variety of its habitats, Nyerere offers an incredible range of activities, from traditional game drives and boat safaris to guided walking tours. The human footprint here is minimal, and the sense of exploration is palpable. Whether you are navigating the intricate channels of the delta or tracking a lion pride through the bush, Nyerere provides a raw and immersive wilderness adventure.\"]','[{\"fact\": \"Nyerere is one of the best places in the world to see the highly endangered and social African wild dog.\", \"name\": \"Wild Dog\", \"image\": \"https://images.unsplash.com/photo-1575550959106-5a7defe28b56?w=640&q=80\", \"likelihood\": \"Common\"}, {\"fact\": \"The Rufiji River is home to massive pods of hippos, which are best seen from a boat safari.\", \"name\": \"Hippo\", \"image\": \"https://images.unsplash.com/photo-1534149043227-d4677db02787?w=640&q=80\", \"likelihood\": \"Very Common\"}, {\"fact\": \"Huge Nile crocodiles bask along the riverbanks and can be seen in the various lakes.\", \"name\": \"Crocodile\", \"image\": \"https://images.unsplash.com/photo-1516298773066-c48f8e9a4842?w=640&q=80\", \"likelihood\": \"Very Common\"}, {\"fact\": \"Large herds move between the river and the inland bush year-round.\", \"name\": \"Elephant\", \"image\": \"https://images.unsplash.com/photo-1557050543-4d5f4e07ef46?w=640&q=80\", \"likelihood\": \"Very Common\"}, {\"fact\": \"Lion prides are frequently found near the lakes and lagoons where prey is abundant.\", \"name\": \"Lion\", \"image\": \"https://images.unsplash.com/photo-1614027164847-1b28cfe1df60?w=640&q=80\", \"likelihood\": \"Common\"}]','[{\"abbr\": \"JAN\", \"band\": \"good\", \"icon\": \"sun\", \"price\": \"$$\", \"crowds\": 2, \"expect\": \"Lush scenery, great boat birding\", \"weather\": \"Hot and green\"}, {\"abbr\": \"FEB\", \"band\": \"good\", \"icon\": \"sun\", \"price\": \"$$\", \"crowds\": 2, \"expect\": \"Wildlife concentrated near the river\", \"weather\": \"Very hot\"}, {\"abbr\": \"MAR\", \"band\": \"good\", \"icon\": \"rain\", \"price\": \"$$\", \"crowds\": 1, \"expect\": \"Emerald landscapes, quiet atmosphere\", \"weather\": \"Short rains\"}, {\"abbr\": \"APR\", \"band\": \"low\", \"icon\": \"rain\", \"price\": \"$\", \"crowds\": 1, \"expect\": \"Many camps close, very lush\", \"weather\": \"Peak rains\"}, {\"abbr\": \"MAY\", \"band\": \"low\", \"icon\": \"rain\", \"price\": \"$\", \"crowds\": 1, \"expect\": \"Quiet, fresh greenery everywhere\", \"weather\": \"Rains finish\"}, {\"abbr\": \"JUN\", \"band\": \"good\", \"icon\": \"sun\", \"price\": \"$$$\", \"crowds\": 3, \"expect\": \"Excellent game viewing begins\", \"weather\": \"Cooler and dry\"}, {\"abbr\": \"JUL\", \"band\": \"peak\", \"icon\": \"sun\", \"price\": \"$$$$\", \"crowds\": 4, \"expect\": \"Peak season for wild dog sightings\", \"weather\": \"Dry and pleasant\"}, {\"abbr\": \"AUG\", \"band\": \"peak\", \"icon\": \"sun\", \"price\": \"$$$$\", \"crowds\": 4, \"expect\": \"Best time for boat safaris\", \"weather\": \"Dry and clear\"}, {\"abbr\": \"SEP\", \"band\": \"peak\", \"icon\": \"sun\", \"price\": \"$$$$\", \"crowds\": 4, \"expect\": \"Intense activity at the riverbanks\", \"weather\": \"Hot and dry\"}, {\"abbr\": \"OCT\", \"band\": \"good\", \"icon\": \"sun\", \"price\": \"$$$\", \"crowds\": 3, \"expect\": \"Golden grass, high wildlife density\", \"weather\": \"Very hot\"}, {\"abbr\": \"NOV\", \"band\": \"good\", \"icon\": \"rain\", \"price\": \"$$\", \"crowds\": 2, \"expect\": \"Birdlife returns, fresh greening\", \"weather\": \"Short rains\"}, {\"abbr\": \"DEC\", \"band\": \"peak\", \"icon\": \"sun\", \"price\": \"$$$$\", \"crowds\": 3, \"expect\": \"Festive vibe, excellent birding\", \"weather\": \"Holiday season\"}]','[{\"name\": \"The River Discovery\", \"dates\": \"June - October\", \"image\": \"https://images.unsplash.com/photo-1549366021-9f761d450615?w=800&q=80\", \"highlights\": [\"Boat safaris\", \"Wild dog action\", \"Dry river drama\"]}, {\"name\": \"The Emerald Delta\", \"dates\": \"November - March\", \"image\": \"https://images.unsplash.com/photo-1516298773066-c48f8e9a4842?w=800&q=80\", \"highlights\": [\"Lush vegetation\", \"Birding peak\", \"No crowds\"]}, {\"name\": \"The Quiet Solitude\", \"dates\": \"April - May\", \"image\": \"https://images.unsplash.com/photo-1535338454528-1b5a4f159e53?w=800&q=80\", \"highlights\": [\"Total wilderness feel\", \"Exclusive access\", \"Dramatic photography\"]}]','[{\"tags\": [\"Water\", \"Iconic\"], \"title\": \"Rufiji River Boat Safari\", \"description\": \"Drift among hippos and crocodiles on Africa\'s most spectacular river safari experience.\"}, {\"tags\": [\"Walking\", \"Adventure\"], \"title\": \"Selous Walking Safari\", \"description\": \"Explore the smaller details of the reserve on foot with an expert guide and armed ranger.\"}, {\"tags\": [\"Adventure\", \"Luxury\"], \"title\": \"Sand River Fly-camping\", \"description\": \"Spend a night under the stars in a remote mobile camp, the ultimate wilderness experience.\"}]','[\"https://images.unsplash.com/photo-1549366021-9f761d450615?w=800&q=80\", \"https://images.unsplash.com/photo-1516298773066-c48f8e9a4842?w=800&q=80\", \"https://images.unsplash.com/photo-1535338454528-1b5a4f159e53?w=800&q=80\"]','{\"visa\": \"Standard Tanzanian eVisa applies\", \"best_time\": \"June to October for boat safaris and game viewing\", \"transport\": \"Exclusively by light aircraft, boat, and 4x4 vehicles\", \"flying_time\": \"45m flight from Dar es Salaam or Zanzibar\"}','[\"ruaha\", \"mikumi\", \"zanzibar\"]','2026-04-03 19:51:45','2026-04-07 09:57:04'),(19,'zanzibar','Zanzibar Archipelago','Coastal Region','The spice islands of white sands and azure waters.','2,462 km²','ISLAND PARADISE','http://localhost:8000/storage/destinations/ySSaOCs4vf0uBvSadzTv394JNFsgH3ZPcDO0jZYM.jpg','http://localhost:8000/storage/destinations/ORAzm9xmXNJjRk09SERBLViY2FPvX088z8CCozV4.jpg','Walking through Stone Town is like stepping back into a layered history written in coral stone and spice-scented air.','published','[{\"icon\": \"sun\", \"label\": \"WEATHER\", \"value\": \"Tropical\"}, {\"icon\": \"calendar\", \"label\": \"PEAK TIME\", \"value\": \"Jun - Feb\"}, {\"icon\": \"thermometer\", \"label\": \"AVG TEMP\", \"value\": \"28°C\"}, {\"icon\": \"map\", \"label\": \"SIZE\", \"value\": \"2,462 km²\"}]','[\"Zanzibar is much more than a tropical island, it is a sensory journey through centuries of layered history. Floating in the turquoise waters of the Indian Ocean, the archipelago is a blend of ancient Swahili culture, fragrant spice plantations, and some of the world\'s most breathtaking white-sand beaches. This is a place where time slows down to the rhythm of the tides and the gentle creak of traditional dhows.\",\"Stone Town, the island\'s historic heart, is a UNESCO World Heritage site known for its labyrinthine alleys, intricately carved teak doors, and bustling spice markets. Every corner tells a story of the Omani sultans, Portuguese explorers, and the rich Swahili heritage that defines the island today. Farther afield, the coastline offers a paradise of palm-fringed beaches, coral reefs teeming with marine life, and the unique Jozani Forest, home to the endemic red colobus monkey.\",\"Whether you are diving in the pristine waters of the Mnemba Atoll, exploring the history of the spice trade, or simply watching the sun set over the Indian Ocean from a beachfront bar, Zanzibar provides the perfect post-safari retreat. It is a place for relaxation, discovery, and an deep immersion into a culture that is as warm and inviting as the tropical sun. The Spice Islands are a world unto themselves.\"]','[{\"fact\": \"Endemic to Zanzibar, these playful monkeys are best seen in the Jozani Chwaka Bay National Park.\", \"name\": \"Red Colobus Monkey\", \"image\": \"https://images.unsplash.com/photo-1555524330-9ec8058309ec?w=640&q=80\", \"likelihood\": \"Common\"}, {\"fact\": \"Frequently seen in effectively protected areas like the Menai Bay Conservation Area.\", \"name\": \"Dolphin\", \"image\": \"https://images.unsplash.com/photo-1590523277543-a94d2e4eb00b?w=640&q=80\", \"likelihood\": \"Common\"}, {\"fact\": \"Green sea turtles nest on several of the archipelago\'s remote beaches and satellite islands.\", \"name\": \"Turtles\", \"image\": \"https://images.unsplash.com/photo-1586861635167-e5223aadc9fe?w=640&q=80\", \"likelihood\": \"Common\"}, {\"fact\": \"A protected population can be visited on Prison Island, some individuals are over 150 years old.\", \"name\": \"Giant Aldabra Tortoise\", \"image\": \"https://images.unsplash.com/photo-1590523277543-a94d2e4eb00b?w=640&q=80\", \"likelihood\": \"Very Common\"}, {\"fact\": \"One of the smallest antelopes in the world, found in the island\'s dry forests and thickets.\", \"name\": \"Suni Antelope\", \"image\": \"https://images.unsplash.com/photo-1546272989-40c92939c6c2?w=640&q=80\", \"likelihood\": \"Rare\"}]','[{\"abbr\": \"JAN\", \"band\": \"peak\", \"icon\": \"sun\", \"price\": \"$$$$\", \"crowds\": 4, \"expect\": \"Perfect beach weather, calm seas\", \"weather\": \"Hot and clear\"}, {\"abbr\": \"FEB\", \"band\": \"peak\", \"icon\": \"sun\", \"price\": \"$$$$\", \"crowds\": 4, \"expect\": \"Ideal for diving and snorkeling\", \"weather\": \"Warm and dry\"}, {\"abbr\": \"MAR\", \"band\": \"good\", \"icon\": \"rain\", \"price\": \"$$$\", \"crowds\": 2, \"expect\": \"Lush scenery, occasional showers\", \"weather\": \"Short rains begin\"}, {\"abbr\": \"APR\", \"band\": \"low\", \"icon\": \"rain\", \"price\": \"$\", \"crowds\": 1, \"expect\": \"Some resorts close, very quiet\", \"weather\": \"Heavy rains\"}, {\"abbr\": \"MAY\", \"band\": \"low\", \"icon\": \"rain\", \"price\": \"$\", \"crowds\": 1, \"expect\": \"Fresh and green, quiet beaches\", \"weather\": \"Rains finish\"}, {\"abbr\": \"JUN\", \"band\": \"good\", \"icon\": \"sun\", \"price\": \"$$$\", \"crowds\": 3, \"expect\": \"Excellent all-round conditions\", \"weather\": \"Cooler and dry\"}, {\"abbr\": \"JUL\", \"band\": \"peak\", \"icon\": \"sun\", \"price\": \"$$$$\", \"crowds\": 5, \"expect\": \"Peak holiday season, lively atmosphere\", \"weather\": \"Sunny and dry\"}, {\"abbr\": \"AUG\", \"band\": \"peak\", \"icon\": \"sun\", \"price\": \"$$$$\", \"crowds\": 5, \"expect\": \"Clear water, perfect for islands\", \"weather\": \"Sunny and dry\"}, {\"abbr\": \"SEP\", \"band\": \"peak\", \"icon\": \"sun\", \"price\": \"$$$$\", \"crowds\": 4, \"expect\": \"Excellent visibility for marine life\", \"weather\": \"Warm and dry\"}, {\"abbr\": \"OCT\", \"band\": \"good\", \"icon\": \"sun\", \"price\": \"$$$\", \"crowds\": 3, \"expect\": \"Golden sunsets, warm waters\", \"weather\": \"Hot and dry\"}, {\"abbr\": \"NOV\", \"band\": \"good\", \"icon\": \"rain\", \"price\": \"$$$\", \"crowds\": 3, \"expect\": \"Dramatic skies, lush palms\", \"weather\": \"Short rains\"}, {\"abbr\": \"DEC\", \"band\": \"peak\", \"icon\": \"sun\", \"price\": \"$$$$\", \"crowds\": 5, \"expect\": \"Festive island celebrations\", \"weather\": \"Hot and festive\"}]','[{\"name\": \"The Sunny Archipelago\", \"dates\": \"December - March\", \"image\": \"https://images.unsplash.com/photo-1590523277543-a94d2e4eb00b?w=800&q=80\", \"highlights\": [\"Calm azure waters\", \"Diving peak\", \"Starlit beach dinners\"]}, {\"name\": \"The Spice Harvest\", \"dates\": \"June - October\", \"image\": \"https://images.unsplash.com/photo-1586861635167-e5223aadc9fe?w=800&q=80\", \"highlights\": [\"Cooler air\", \"Historic tours\", \"Vibrant markets\"]}, {\"name\": \"The Emerald Tide\", \"dates\": \"April - May\", \"image\": \"https://images.unsplash.com/photo-1590523277543-a94d2e4eb00b?w=800&q=80\", \"highlights\": [\"Quiet retreats\", \"Lush gardens\", \"Dramatic beachscapes\"]}]','[{\"tags\": [\"History\", \"Culture\"], \"title\": \"Stone Town Walking Tour\", \"description\": \"Explore the historic alleys and hidden gems of the ancient island capital with a local guide.\"}, {\"tags\": [\"Senses\", \"Discovery\"], \"title\": \"Spice Plantation Exploration\", \"description\": \"See, smell, and taste the world-famous spices that gave the island its name and shaped its history.\"}, {\"tags\": [\"Relax\", \"Romance\"], \"title\": \"Sunset Dhow Cruise\", \"description\": \"Sail on a traditional wooden boat as the sun sets over the Indian Ocean, with traditional music and snacks.\"}]','[\"https://images.unsplash.com/photo-1586861635167-e5223aadc9fe?w=800&q=80\", \"https://images.unsplash.com/photo-1590523277543-a94d2e4eb00b?w=800&q=80\", \"https://images.unsplash.com/photo-1586861635167-e5223aadc9fe?w=800&q=80\"]','{\"visa\": \"Standard Tanzanian eVisa applies\", \"best_time\": \"June to February for beach weather and diving\", \"transport\": \"Standard vehicles, traditional dhows, and ferries\", \"flying_time\": \"15m flight from Dar es Salaam or 1h from Arusha\"}','[\"selous\", \"mikumi\", \"serengeti\"]','2026-04-03 19:51:46','2026-04-07 10:03:22'),(20,'mikumi','Mikumi National Park','Southern Circuit','The \"Little Serengeti\" of the south.','3,230 km²','SOUTHERN GEM','http://localhost:8000/storage/destinations/qtqJlZq2QkOvPbmg55Nz5PIc9IGmTvi5OX5ODjDP.jpg','http://localhost:8000/storage/destinations/nBrtrQUEzm1IiznmDOWsnPVijAtPuWWIW0BO1BcC.jpg','The open Mkata Plains offer a visibility and wildlife density that rivals the legendary Serengeti.','published','[{\"icon\": \"paw\", \"label\": \"WILDLIFE\", \"value\": \"Elephants\"}, {\"icon\": \"calendar\", \"label\": \"PEAK TIME\", \"value\": \"Year-round\"}, {\"icon\": \"thermometer\", \"label\": \"AVG TEMP\", \"value\": \"28°C\"}, {\"icon\": \"map\", \"label\": \"SIZE\", \"value\": \"3.2K km²\"}]','[\"Mikumi National Park is the gateway to the Southern Circuit and is often affectionately called the \'Little Serengeti\' due to its open floodplains and incredible wildlife density. Located between the Uluguru Mountains and the Lumango Range, the park is divided by the main road into two distinct sectors, with the northern Mkata Plains being the most wildlife-rich area.\",\"The Mkata Plains are home to massive herds of buffalo, zebra, and wildebeest, which in turn attract large prides of lions. The park is also famous for its \'Mikumi Lions\', which are often found resting in the branches of acacia trees, a behavior usually associated with Lake Manyara. Elephants move through the park in large family groups, and the hippo pools provide reliable sightings of these aquatic giants wallowing in the mud.\",\"What makes Mikumi increasingly accessible is its connection to the new SGR high-speed train from Dar es Salaam. Travellers can now reach the park in a fraction of the time it used to take by road, making it the perfect getaway for those staying in the city or as a high-impact start to a longer southern safari adventure.\"]','[{\"fact\": \"Famous for their habit of resting in trees and their preference for the open Mkata Plains.\", \"name\": \"Lion\", \"image\": \"https://images.unsplash.com/photo-1614027164847-1b28cfe1df60?w=640&q=80\", \"likelihood\": \"Very Common\"}, {\"fact\": \"Large herds move across the plains, often seen near the park\'s waterholes.\", \"name\": \"Elephant\", \"image\": \"https://images.unsplash.com/photo-1557050543-4d5f4e07ef46?w=640&q=80\", \"likelihood\": \"Very Common\"}, {\"fact\": \"Massive herds congregate near the Mkata riverbed during the dry season.\", \"name\": \"Buffalo\", \"image\": \"https://images.unsplash.com/photo-1549366021-9f761d450615?w=640&q=80\", \"likelihood\": \"Very Common\"}, {\"fact\": \"The Maasai giraffe is found in abundance throughout the acacia woodlands.\", \"name\": \"Giraffe\", \"image\": \"https://images.unsplash.com/photo-1555524330-9ec8058309ec?w=640&q=80\", \"likelihood\": \"Common\"}, {\"fact\": \"The largest antelope in Africa is frequently seen in the park\'s more open areas.\", \"name\": \"Eland\", \"image\": \"https://images.unsplash.com/photo-1546272989-40c92939c6c2?w=640&q=80\", \"likelihood\": \"Common\"}]','[{\"abbr\": \"JAN\", \"band\": \"good\", \"icon\": \"sun\", \"price\": \"$$\", \"crowds\": 2, \"expect\": \"Lush savanna, active birdlife\", \"weather\": \"Warm and green\"}, {\"abbr\": \"FEB\", \"band\": \"good\", \"icon\": \"sun\", \"price\": \"$$\", \"crowds\": 2, \"expect\": \"Good sightings at hippo pools\", \"weather\": \"Hot and clear\"}, {\"abbr\": \"MAR\", \"band\": \"good\", \"icon\": \"rain\", \"price\": \"$$\", \"crowds\": 1, \"expect\": \"Emerald landscapes, calm atmosphere\", \"weather\": \"Short rains\"}, {\"abbr\": \"APR\", \"band\": \"low\", \"icon\": \"rain\", \"price\": \"$\", \"crowds\": 1, \"expect\": \"Lush but challenging road conditions\", \"weather\": \"Heavy rains\"}, {\"abbr\": \"MAY\", \"band\": \"low\", \"icon\": \"rain\", \"price\": \"$\", \"crowds\": 1, \"expect\": \"Solitude and vibrant photography\", \"weather\": \"Quiet rains\"}, {\"abbr\": \"JUN\", \"band\": \"good\", \"icon\": \"sun\", \"price\": \"$$$\", \"crowds\": 3, \"expect\": \"Excellent game viewing begins\", \"weather\": \"Dry and crisp\"}, {\"abbr\": \"JUL\", \"band\": \"peak\", \"icon\": \"sun\", \"price\": \"$$$$\", \"crowds\": 4, \"expect\": \"Peak season for lion sightings\", \"weather\": \"Cool and dry\"}, {\"abbr\": \"AUG\", \"band\": \"peak\", \"icon\": \"sun\", \"price\": \"$$$$\", \"crowds\": 4, \"expect\": \"High wildlife concentration at water\", \"weather\": \"Dry and clear\"}, {\"abbr\": \"SEP\", \"band\": \"peak\", \"icon\": \"sun\", \"price\": \"$$$$\", \"crowds\": 4, \"expect\": \"Best time for predator action\", \"weather\": \"Warm and dry\"}, {\"abbr\": \"OCT\", \"band\": \"good\", \"icon\": \"sun\", \"price\": \"$$$\", \"crowds\": 3, \"expect\": \"Golden grass, intense blue horizons\", \"weather\": \"Warming up\"}, {\"abbr\": \"NOV\", \"band\": \"good\", \"icon\": \"rain\", \"price\": \"$$\", \"crowds\": 2, \"expect\": \"Fresh greening of the plains\", \"weather\": \"Short rains\"}, {\"abbr\": \"DEC\", \"band\": \"peak\", \"icon\": \"sun\", \"price\": \"$$$$\", \"crowds\": 3, \"expect\": \"Festive safari vibe in central\", \"weather\": \"Holiday season\"}]','[{\"name\": \"The Big Game Window\", \"dates\": \"June - September\", \"image\": \"https://images.unsplash.com/photo-1549366021-9f761d450615?w=800&q=80\", \"highlights\": [\"Elephant herds\", \"Lion hunting\", \"Best visibility\"]}, {\"name\": \"The Birding Emerald\", \"dates\": \"November - March\", \"image\": \"https://images.unsplash.com/photo-1516298773066-c48f8e9a4842?w=800&q=80\", \"highlights\": [\"Migratory birds\", \"Lush scenery\", \"No crowds\"]}, {\"name\": \"Weekend Rail Getaway\", \"dates\": \"Year-round\", \"image\": \"https://images.unsplash.com/photo-1535338454528-1b5a4f159e53?w=800&q=80\", \"highlights\": [\"SGR train journey\", \"Quick access\", \"Family friendly\"]}]','[{\"tags\": [\"Wildlife\", \"Iconic\"], \"title\": \"Mkata Plains Game Drive\", \"description\": \"Patrol the vast open plains where wildlife concentration is at its highest, including the famous tree-climbing lions.\"}, {\"tags\": [\"Wildlife\", \"Water\"], \"title\": \"Hippo Pool Visit\", \"description\": \"Observe large pods of hippos and crocodiles from the safety of a designated viewpoint near the Mkata River.\"}, {\"tags\": [\"Rail\", \"Travel\"], \"title\": \"SGR Train Safari\", \"description\": \"Combine your safari with a journey on the modern SGR high-speed train, a comfortable and scenic way to reach the park.\"}]','[\"https://images.unsplash.com/photo-1516298773066-c48f8e9a4842?w=800&q=80\", \"https://images.unsplash.com/photo-1549366021-9f761d450615?w=800&q=80\", \"https://images.unsplash.com/photo-1535338454528-1b5a4f159e53?w=800&q=80\"]','{\"visa\": \"Standard Tanzanian eVisa applies\", \"best_time\": \"June to September for large herds and predators\", \"transport\": \"Accessible by rail, road, or light aircraft\", \"flying_time\": \"1.5h by SGR train from Dar es Salaam or 4h drive\"}','[\"selous\", \"ruaha\", \"zanzibar\"]','2026-04-03 19:51:46','2026-04-07 09:54:43');
