INSERT INTO `faq_categories` VALUES (1,'planning','Planning Your Safari','compass','Choosing the right safari, season, and itinerary',1,'2026-04-03 19:51:46','2026-04-03 19:51:46'),(2,'booking','Booking & Payments','calendar','Deposits, payment, cancellations, and confirmation',2,'2026-04-03 19:51:46','2026-04-03 19:51:46'),(3,'health','Health & Safety','shield','Vaccinations, malaria, safety, and medical considerations',3,'2026-04-03 19:51:46','2026-04-03 19:51:46'),(4,'on-safari','What to Expect on Safari','binoculars','Daily life, wildlife, comfort, and what surprises people',4,'2026-04-03 19:51:46','2026-04-03 19:51:46'),(5,'kilimanjaro','Kilimanjaro Questions','mountain','Routes, altitude sickness, fitness requirements, and summit success',5,'2026-04-03 19:51:46','2026-04-03 19:51:46'),(6,'zanzibar','Zanzibar Questions','dhow','Beaches, culture, activities, and getting there',6,'2026-04-03 19:51:46','2026-04-03 19:51:46'),(7,'responsible','Responsible Travel','leaf','Conservation, community impact, and ethical choices',7,'2026-04-03 19:51:46','2026-04-03 19:51:46'),(8,'ronjoo','Working With Ronjoo','handshake','Our team, our approach, and what sets us apart',8,'2026-04-03 19:51:46','2026-04-03 19:51:46');
