LOCK TABLES `faqs` WRITE;
/*!40000 ALTER TABLE `faqs` DISABLE KEYS */;
INSERT INTO `faqs` VALUES (1,1,'When is the best time to visit Tanzania?','Tanzania is a year-round destination, but different seasons offer radically different experiences. **June–October** is the dry season, peak wildlife visibility, the Mara River crossings of the Great Migration, and clear golden-hour skies. **January–February** delivers the calving season in Ndutu. **March–May** is the long rains, lowest prices, lush landscapes. **November–December** is the short rains, excellent birding, baby animals, beautiful green scenery.','[\"seasons\", \"planning\"]','published','{\"href\": \"/travel-resources/best-time-to-visit\", \"label\": \"Best Time to Visit Tanzania\"}',NULL,1,'2026-04-03 19:51:46','2026-04-03 19:51:46'),(2,1,'How far in advance should I book?','For peak season travel (July–October and January–February), we recommend booking **6–12 months in advance**. The best lodges and camps sell their peak dates first. For shoulder and low season, 3–6 months is typically sufficient.','[\"booking\", \"planning\"]','published',NULL,NULL,2,'2026-04-03 19:51:46','2026-04-03 19:51:46'),(3,1,'How long should my safari be?','The minimum meaningful safari is 4 nights. However, we recommend a **minimum of 6 nights** for first-time visitors to Tanzania. This allows for three parks, genuine wildlife encounters, and time to settle into the rhythm of the bush.','[\"duration\", \"planning\"]','published',NULL,NULL,3,'2026-04-03 19:51:46','2026-04-03 19:51:46'),(4,1,'What is the difference between a private safari and a group departure?','A **private safari** means the vehicle, guide, and itinerary are exclusively yours. A **group departure** means you book remaining seats on a pre-scheduled safari with other independent travelers, maximum 8 guests per vehicle. Both options use the same private Ronjoo guides and partner accommodations.','[\"private\", \"group\"]','published',NULL,NULL,4,'2026-04-03 19:51:46','2026-04-03 19:51:46'),(5,1,'Which parks should I include in my first safari?','For a first Tanzania safari: **Tarangire** (elephants, baobabs), **Ngorongoro Crater** (Big Five density, black rhino), and the **Serengeti** (open plains, big cats, migration). These three parks form the classic Tanzania safari.','[\"parks\", \"first-timer\"]','published',NULL,'{\"href\": \"/safaris/northern-circuit-classic\", \"label\": \"Northern Circuit Classic\"}',5,'2026-04-03 19:51:46','2026-04-03 19:51:46'),(6,2,'How do I book a safari with Ronjoo?','Submit an enquiry through the booking form on any safari page or via WhatsApp. A safari specialist will respond within 4 hours. Your booking is confirmed on receipt of the 30% deposit. We do not charge booking fees.','[\"booking\"]','published',NULL,NULL,1,'2026-04-03 19:51:46','2026-04-03 19:51:46'),(7,2,'How much deposit is required?','A **30% deposit** of the total safari cost is required to confirm your booking. Full payment is due 60 days before your departure date. For bookings made within 60 days, full payment is required at booking.','[\"deposit\", \"payment\"]','published',NULL,NULL,2,'2026-04-03 19:51:46','2026-04-03 19:51:46'),(8,2,'What payment methods do you accept?','We accept Visa, Mastercard, and American Express via Stripe. We also accept PayPal and international bank transfer (SWIFT). All prices are in USD. Card payments incur no additional surcharge.','[\"payment\"]','published',NULL,NULL,3,'2026-04-03 19:51:46','2026-04-03 19:51:46'),(9,2,'What is your cancellation policy?','**90+ days**: Full deposit refunded minus $150 processing fee. **60–89 days**: 50% deposit refunded. **30–59 days**: Deposit non-refundable. **Under 30 days**: 75% of total non-refundable. **Under 14 days**: 100% non-refundable. We strongly recommend comprehensive travel insurance.','[\"cancellation\"]','published',NULL,NULL,4,'2026-04-03 19:51:46','2026-04-03 19:51:46'),(10,3,'Do I need malaria tablets for Tanzania?','Yes. Tanzania is a malaria-endemic country and antimalarial prophylaxis is strongly recommended. The most commonly prescribed options are Atovaquone-Proguanil (Malarone), Doxycycline, and Mefloquine. Consult your doctor at least 6 weeks before departure.','[\"health\", \"malaria\"]','published','{\"href\": \"/travel-resources/health-vaccinations\", \"label\": \"Health & Vaccinations Tanzania\"}',NULL,1,'2026-04-03 19:51:46','2026-04-03 19:51:46'),(11,3,'What vaccinations do I need?','Recommended: **Hepatitis A and B**, **Typhoid**, updated **Tetanus-Diphtheria**. **Yellow Fever** vaccination is required if arriving from a yellow-fever endemic country. Consult a travel health specialist 6–8 weeks before departure.','[\"health\", \"vaccinations\"]','published',NULL,NULL,2,'2026-04-03 19:51:46','2026-04-03 19:51:46'),(12,3,'Is Tanzania safe for travelers?','Tanzania has one of the most stable political environments in East Africa and is consistently considered safe for tourists. Safari areas are managed and secure. You are accompanied by a Ronjoo guide during all safari activities.','[\"safety\"]','published',NULL,NULL,3,'2026-04-03 19:51:46','2026-04-03 19:51:46'),(13,4,'What does a typical safari day look like?','**5:30–6:00am**: Wake-up call. **6:00–6:30am**: Morning game drive. **10:00–11:00am**: Hot breakfast. **11:00am–3:00pm**: Rest at camp. **3:30–4:00pm**: Afternoon game drive. **6:30–7:00pm**: Sundowner drinks and dinner.','[\"daily-life\"]','published',NULL,NULL,1,'2026-04-03 19:51:46','2026-04-03 19:51:46'),(14,4,'How close will we get to the animals?','Closer than you expect. In Tanzania\'s national parks, wildlife has become habituated to safari vehicles over decades. Lions will sleep within 3 meters. Elephants will walk past your open door.','[\"wildlife\"]','published',NULL,NULL,2,'2026-04-03 19:51:46','2026-04-03 19:51:46'),(15,4,'What are the lodges and camps like?','Our partner lodges range from classic tented camps (permanent canvas structures with en-suite bathrooms) to luxury lodges with private plunge pools. Luxury tented camps in Africa are not camping, they are among the finest accommodation experiences in the world.','[\"accommodation\"]','published',NULL,NULL,3,'2026-04-03 19:51:46','2026-04-03 19:51:46'),(16,5,'Which Kilimanjaro route is best?','The **Lemosho Route** is our top recommendation, highest summit success rates (85–90%), most varied scenery, and gradual acclimatization. The Machame Route is excellent for experienced trekkers. The Marangu Route has the lowest success rate.','[\"routes\"]','published',NULL,'{\"href\": \"/safaris/kilimanjaro-lemosho\", \"label\": \"Kilimanjaro Lemosho Route\"}',1,'2026-04-03 19:51:46','2026-04-03 19:51:46'),(17,5,'What is the summit success rate?','On our 9-day Lemosho Route, Ronjoo\'s summit success rate is **87%**. The single most significant factor in summit success is route length, longer routes allow better acclimatization.','[\"summit\"]','published',NULL,NULL,2,'2026-04-03 19:51:46','2026-04-03 19:51:46'),(18,6,'Is Zanzibar worth including in a Tanzania safari?','Unequivocally yes. Tanzania is one of the only destinations on Earth where you can combine world-class wildlife safari and Indian Ocean beaches within a 25-minute flight. We recommend minimum 3 beach nights.','[\"zanzibar\"]','published',NULL,NULL,1,'2026-04-03 19:51:46','2026-04-03 19:51:46'),(19,6,'What is the best beach area in Zanzibar?','**Nungwi and Kendwa** (north): Best all-round beach. **Paje and Matemwe** (east): Excellent for kitesurfing. **Michamvi and Bwejuu** (southeast): Quieter, ideal for couples.','[\"beaches\"]','published',NULL,NULL,2,'2026-04-03 19:51:46','2026-04-03 19:51:46'),(20,7,'How does safari tourism help conservation?','Well-managed wildlife tourism is the most powerful economic argument for protecting wild land. Tanzania\'s national park system is funded substantially by tourism revenues.','[\"conservation\"]','published',NULL,NULL,1,'2026-04-03 19:51:46','2026-04-03 19:51:46'),(21,8,'How long has Ronjoo Safaris been operating?','Ronjoo Safaris has been operating from Arusha, Tanzania since 2010, over **18 years** of specialist Tanzania safari experience. Over 4,200 guests from 60+ countries, 4.9-star rating.','[\"about\"]','published',NULL,NULL,1,'2026-04-03 19:51:46','2026-04-03 19:51:46'),(22,8,'Are your guides licensed?','All Ronjoo guides hold current Tanzania Wildlife Authority Professional Guiding Licences (Class A), the highest category. All complete Ronjoo\'s internal training program. Many have 15+ years of experience.','[\"guides\"]','published',NULL,NULL,2,'2026-04-03 19:51:46','2026-04-03 19:51:46');
/*!40000 ALTER TABLE `faqs` ENABLE KEYS */;
UNLOCK TABLES;

