INSERT INTO `itinerary_days` VALUES (402,70,1,'Arrival into Mwanza Airport','North Serengeti','Arrive at Mwanza Airport. Drive to Northern Serengeti. Check into your luxury camp. Afternoon relaxation and short game walk.','[\"Transfer\"]','D',NULL,'One Nature Camp',NULL,NULL,NULL,'FB basis, 3 nights','2026-04-07 11:00:07','2026-04-07 11:00:07'),(403,70,2,'North Serengeti Game Drive','North Serengeti','Full day exploring Northern Serengeti. Search for predators along the Grumeti River. Visit the Mara River area.','[\"Game Drive\"]','B/L/D',NULL,'One Nature Camp',NULL,NULL,NULL,'Second night','2026-04-07 11:00:07','2026-04-07 11:00:07'),(404,70,3,'North Serengeti Exploration','North Serengeti','Another full day in Northern Serengeti. Focus on the Mara River ecosystem and its resident wildlife.','[\"Game Drive\"]','B/L/D',NULL,'One Nature Camp',NULL,NULL,NULL,'Third night','2026-04-07 11:00:07','2026-04-07 11:00:07'),(405,70,4,'Drive to Central Serengeti','Central Serengeti','Morning game drive enroute to Central Serengeti. Arrive at your new camp in the Seronera area.','[\"Game Drive\", \"Transfer\"]','B/L/D',NULL,'Warangi Ridge',NULL,NULL,NULL,'FB basis, 2 nights','2026-04-07 11:00:07','2026-04-07 11:00:07'),(406,70,5,'Central Serengeti Game Drive','Central Serengeti','Full day exploring Central Serengeti. This area is famous for its year-round wildlife.','[\"Game Drive\"]','B/L/D',NULL,'Warangi Ridge',NULL,NULL,NULL,'Second night in Central','2026-04-07 11:00:07','2026-04-07 11:00:07'),(407,70,6,'Ngorongoro Crater','Ngorongoro Conservation Area','Drive to Ngorongoro. Afternoon crater game drive.','[\"Game Drive\"]','B/L/D',NULL,'Craters Edge',NULL,NULL,NULL,'HB basis','2026-04-07 11:00:07','2026-04-07 11:00:07'),(408,70,7,'Departure to Kilimanjaro/Arusha','Arusha','Morning transfer to Kilimanjaro/Arusha Airport.','[\"Transfer\"]','B',NULL,NULL,NULL,NULL,NULL,'Safari ends','2026-04-07 11:00:07','2026-04-07 11:00:07'),(409,72,1,'Arrival into Kilimanjaro/Arusha','Arusha','Arrive at Kilimanjaro International Airport. Transfer to your Arusha lodge.','[\"Transfer\"]','B',NULL,'Coffee Lodge Arusha',NULL,NULL,NULL,'HB basis, 2 nights','2026-04-07 11:01:51','2026-04-07 11:01:51'),(410,72,2,'Kilimanjaro West Day Trip','Kilimanjaro West','Full day trip to Kilimanjaro West region. Scenic views and cultural experiences.','[\"Cultural\"]','B/L/D',NULL,'Coffee Lodge Arusha',NULL,NULL,NULL,'Second night in Arusha','2026-04-07 11:01:51','2026-04-07 11:01:51'),(411,72,3,'Tarangire Game Drive','Tarangire National Park','Drive to Tarangire for full day game drive.','[\"Game Drive\"]','B/L/D',NULL,'Neptune Lodge Karatu',NULL,NULL,NULL,'FB basis','2026-04-07 11:01:51','2026-04-07 11:01:51'),(412,72,4,'Enroute to Serengeti','Serengeti National Park','Drive to Serengeti with enroute game drives.','[\"Game Drive\", \"Transfer\"]','B/L/D',NULL,'Neptune Camps Central Serengeti',NULL,NULL,NULL,'FB basis, 2 nights','2026-04-07 11:01:51','2026-04-07 11:01:51'),(413,72,5,'Full Day Serengeti','Serengeti National Park','Full day game drive in Serengeti.','[\"Game Drive\"]','B/L/D',NULL,'Neptune Camps Central Serengeti',NULL,NULL,NULL,'Second night','2026-04-07 11:01:51','2026-04-07 11:01:51'),(414,72,6,'Serengeti to Ngorongoro','Ngorongoro Conservation Area','Enroute game drive to Ngorongoro area.','[\"Game Drive\", \"Transfer\"]','B/L/D',NULL,'Neptune Lodge Karatu',NULL,NULL,NULL,'FB basis, 2 nights','2026-04-07 11:01:51','2026-04-07 11:01:51'),(415,72,7,'Ngorongoro Crater','Ngorongoro Conservation Area','Full crater game drive.','[\"Game Drive\"]','B/L/D',NULL,'Neptune Lodge Karatu',NULL,NULL,NULL,'Second night at Karatu','2026-04-07 11:01:51','2026-04-07 11:01:51'),(416,72,8,'Fly to Zanzibar','Zanzibar','Transfer to Arusha Airport for flight to Zanzibar. Meet and transfer to your beach resort.','[\"Fly\", \"Transfer\"]','B',NULL,'Neptune Resort Pwani',NULL,NULL,NULL,'AI basis, 7 nights in Zanzibar','2026-04-07 11:01:51','2026-04-07 11:01:51'),(417,72,9,'Zanzibar Beach Relaxation','Zanzibar','Full day at leisure on Zanzibar beaches. Optional snorkeling, diving, or Stone Town tour.','[\"Beach\"]','B/L/D',NULL,'Neptune Resort Pwani',NULL,NULL,NULL,'All Inclusive','2026-04-07 11:01:51','2026-04-07 11:01:51'),(418,72,10,'Zanzibar Free Day','Zanzibar','Day at leisure. Enjoy the resort facilities or explore Zanzibar.','[\"Beach\"]','B/L/D',NULL,'Neptune Resort Pwani',NULL,NULL,NULL,'All Inclusive','2026-04-07 11:01:51','2026-04-07 11:01:51'),(419,72,11,'Zanzibar Free Day','Zanzibar','Day at leisure.','[\"Beach\"]','B/L/D',NULL,'Neptune Resort Pwani',NULL,NULL,NULL,'All Inclusive','2026-04-07 11:01:51','2026-04-07 11:01:51'),(420,72,12,'Zanzibar Free Day','Zanzibar','Day at leisure.','[\"Beach\"]','B/L/D',NULL,'Neptune Resort Pwani',NULL,NULL,NULL,'All Inclusive','2026-04-07 11:01:51','2026-04-07 11:01:51'),(421,72,13,'Zanzibar Free Day','Zanzibar','Final full day in Zanzibar. Sunset dhow cruise optional.','[\"Beach\"]','B/L/D',NULL,'Neptune Resort Pwani',NULL,NULL,NULL,'All Inclusive','2026-04-07 11:01:51','2026-04-07 11:01:51'),(422,72,14,'Departure from Zanzibar','Zanzibar','Transfer to Zanzibar Airport for your onward journey.','[\"Transfer\"]','B',NULL,NULL,NULL,NULL,NULL,'Holiday ends','2026-04-07 11:01:51','2026-04-07 11:01:51'),(423,71,1,'Fly into Seronera Airstrip','Central Serengeti','Fly from Arusha to Seronera Airstrip in Central Serengeti. Meet your guide and transfer to camp. Afternoon game drive.','[\"Fly\", \"Game Drive\"]','L/D',NULL,'Envi Sisini Camp',NULL,NULL,NULL,'FB basis, 3 nights','2026-04-07 11:04:00','2026-04-07 11:04:00'),(424,71,2,'Full Day Serengeti Game Drive','Central Serengeti','Full day exploring Central Serengeti. Search for the Big Five and witness predator-prey dynamics.','[\"Game Drive\"]','B/L/D',NULL,'Envi Sisini Camp',NULL,NULL,NULL,'Second night','2026-04-07 11:04:00','2026-04-07 11:04:00'),(425,71,3,'Serengeti Exploration','Central Serengeti','Another full day in Serengeti. Visit kopjes, river crossings, and open plains.','[\"Game Drive\"]','B/L/D',NULL,'Envi Sisini Camp',NULL,NULL,NULL,'Third night','2026-04-07 11:04:00','2026-04-07 11:04:00'),(426,71,4,'Fly from Seronera Airstrip','Central Serengeti','Morning game drive enroute to airstrip. Fly back to Arusha.','[\"Game Drive\", \"Fly\"]','B',NULL,NULL,NULL,NULL,NULL,'Safari ends','2026-04-07 11:04:00','2026-04-07 11:04:00'),(427,75,1,'Dar es Salaam to Mikumi via SGR','Mikumi National Park','Early arrival at SGR station in Dar es Salaam. Comfortable train ride to Morogoro. Meet your guide and transfer to Mikumi (1.5 hours). Half-day game drive in Mikumi. Look for elephants, zebras, giraffes, lions, and buffaloes. Picnic lunch at waterhole. Evening transfer to lodge.','[\"Transfer\", \"Game Drive\"]','L/D',NULL,'Vuma Hills Mikumi',NULL,NULL,NULL,'Full Board, 2 nights','2026-04-07 11:06:22','2026-04-07 11:06:22'),(428,75,2,'Full Day Mikumi Game Drive','Mikumi National Park','Full day exploring Mikumi\'s diverse habitats. Visit Mkata Floodplain for large herbivore herds. Picnic lunch in the park. Afternoon visit to Hippo Pool.','[\"Game Drive\"]','B/L/D',NULL,'Vuma Hills Mikumi',NULL,NULL,NULL,'Second night','2026-04-07 11:06:22','2026-04-07 11:06:22'),(429,75,3,'Mikumi to Dar es Salaam via SGR','Mikumi National Park','Optional morning game drive or nature walk. Check out and transfer to Morogoro train station. Return SGR train to Dar es Salaam.','[\"Game Drive\", \"Transfer\"]','B',NULL,NULL,NULL,NULL,NULL,'Safari ends','2026-04-07 11:06:22','2026-04-07 11:06:22'),(430,74,1,'Arrival at Ruaha National Park','Ruaha National Park','A Rickshaw Travel representative will pick you up from Msembe Airstrip and drive to Ruaha River Lodge for check in and relaxation at the camp.','[\"Fly\", \"Transfer\"]','B/L/D',NULL,'Ruaha River Lodge',NULL,NULL,NULL,'Full Board basis, 3 nights','2026-04-07 11:08:13','2026-04-07 11:08:13'),(431,74,2,'Full Day Game Drive','Ruaha National Park','Easy day after breakfast, enjoy a full day game drive with picnic lunch. Dinner and overnight at Ruaha River Lodge.','[\"Game Drive\"]','B/L/D',NULL,'Ruaha River Lodge',NULL,NULL,NULL,'Second night','2026-04-07 11:08:13','2026-04-07 11:08:13'),(432,74,3,'Game Drive & Balloon Safari Option','Ruaha National Park','After breakfast, enjoy a full day game drive with picnic lunch. Optional hot air balloon safari at dawn (July-October only).','[\"Game Drive\"]','B/L/D',NULL,'Ruaha River Lodge',NULL,NULL,NULL,'Third night','2026-04-07 11:08:13','2026-04-07 11:08:13'),(433,74,4,'Departure','Ruaha National Park','After breakfast, a Rickshaw Representative will drive you to the airstrip for your flight back to Dar es salaam.','[\"Fly\", \"Transfer\"]','B',NULL,NULL,NULL,NULL,NULL,'Safari ends','2026-04-07 11:08:13','2026-04-07 11:08:13'),(434,73,1,'Dar es Salaam to Selous (Nyerere)','Selous Game Reserve','Depart from Dar es Salaam airport to Mtemere Airstrip. Transfer to Serena Mivumo River Camp. Depart for a full-day safari with packed lunch. Explore Selous Game Reserve, known for African wild dogs. Bush lunch with a view of wildlife. Return to camp for dinner.','[\"Fly\", \"Game Drive\", \"Transfer\"]','B/L/D',NULL,'Serena Mivumo River Camp',NULL,NULL,NULL,'Full Board basis, 3 nights','2026-04-07 11:10:12','2026-04-07 11:10:12'),(435,73,2,'Bush Walk - Selous','Selous Game Reserve','Breakfast at Serena Mivumo River Camp. Morning safari activity with an experienced guide: bush walk through the reserve. Lunch with stunning lake views. Leisure on your own in the afternoon. Return to camp for dinner.','[\"Walking\", \"Game Drive\"]','B/L/D',NULL,'Serena Mivumo River Camp',NULL,NULL,NULL,'Second night','2026-04-07 11:10:12','2026-04-07 11:10:12'),(436,73,3,'Excursions - Game Drive or Boat','Selous Game Reserve','Breakfast at camp, followed by guided walk. Choose between game drive or boat excursion on the Rufiji River system.','[\"Walking\", \"Game Drive\", \"Boat\"]','B/L/D',NULL,'Serena Mivumo River Camp',NULL,NULL,NULL,'Third night','2026-04-07 11:10:12','2026-04-07 11:10:12'),(437,73,4,'Departure to Dar es Salaam','Selous Game Reserve','Check-out and transfer to Mtemere Airstrip. Depart on a scheduled return flight to Dar es Salaam.','[\"Fly\", \"Transfer\"]','B',NULL,NULL,NULL,NULL,NULL,'Safari ends','2026-04-07 11:10:12','2026-04-07 11:10:12'),(438,67,1,'Arrival into Kilimanjaro/Arusha','Arusha','Arrive at Kilimanjaro International Airport. Meet your guide and transfer to your Arusha hotel. Overnight stay and preparation for safari.','[\"Transfer\"]','B',NULL,'Legendary Lodge Arusha',NULL,NULL,NULL,'BB basis','2026-04-07 11:11:52','2026-04-07 11:11:52'),(439,67,2,'Enroute Game Drive to Serengeti','Serengeti National Park','Drive to Serengeti via Ngorongoro Conservation Area. Enroute game drives and scenic views. Arrive at Central Serengeti lodge for 2 nights.','[\"Game Drive\", \"Transfer\"]','B/L/D',NULL,'Serengeti Explorer',NULL,NULL,NULL,'FB basis, 2 nights','2026-04-07 11:11:52','2026-04-07 11:11:52'),(440,67,3,'Full Day Serengeti Game Drive','Serengeti National Park','Full day exploring Serengeti\'s diverse ecosystems. Search for lions, leopards, cheetahs, elephants, and buffalo. Picnic lunch in the bush.','[\"Game Drive\"]','B/L/D',NULL,'Serengeti Explorer',NULL,NULL,NULL,'Second night in Serengeti','2026-04-07 11:11:52','2026-04-07 11:11:52'),(441,67,4,'Ngorongoro Crater Game Drive','Ngorongoro Conservation Area','Morning drive to Ngorongoro Crater. Descend 600m to the crater floor for exceptional game viewing. Visit a Maasai boma in the afternoon.','[\"Game Drive\", \"Cultural\"]','B/L/D',NULL,'The Manor Karatu',NULL,NULL,NULL,'HB basis','2026-04-07 11:11:52','2026-04-07 11:11:52'),(442,67,5,'Departure','Arusha','Morning transfer to Kilimanjaro/Arusha Airport for your onward journey.','[\"Transfer\"]','B',NULL,NULL,NULL,NULL,NULL,'Safari ends','2026-04-07 11:11:52','2026-04-07 11:11:52'),(443,68,1,'Arrival & Arusha National Park','Arusha National Park','Arrive at Kilimanjaro/Arusha Airport. Meet your guide and enjoy a game drive in Arusha National Park. Home to colobus monkeys, giraffes, and stunning views of Mount Meru.','[\"Game Drive\", \"Transfer\"]','B/L/D',NULL,'Coffee Lodge Arusha',NULL,NULL,NULL,'BB basis at lodge','2026-04-07 11:13:11','2026-04-07 11:13:11'),(444,68,2,'Tarangire Game Drive','Tarangire National Park','Morning drive to Tarangire National Park. Full day game drive exploring this elephant paradise. Ancient baobab trees and diverse wildlife. Evening transfer to Karatu.','[\"Game Drive\"]','B/L/D',NULL,'Ngorongoro Oldeani Lodge',NULL,NULL,NULL,'FB basis','2026-04-07 11:13:11','2026-04-07 11:13:11'),(445,68,3,'Ngorongoro Crater & Departure','Ngorongoro Conservation Area','Early morning crater game drive. Explore the Ngorongoro Crater floor with its dense wildlife population. Afternoon transfer to Kilimanjaro/Arusha Airport.','[\"Game Drive\", \"Transfer\"]','B/L',NULL,NULL,NULL,NULL,NULL,'Safari ends','2026-04-07 11:13:11','2026-04-07 11:13:11'),(446,69,1,'Arrival & Tarangire Game Drive','Tarangire National Park','Arrive at Kilimanjaro/Arusha Airport. Drive directly to Tarangire National Park for afternoon game drive. Look for elephants, lions, zebras, and giraffes.','[\"Game Drive\", \"Transfer\"]','L/D',NULL,'Neptune Lodge Karatu',NULL,NULL,NULL,'FB basis','2026-04-07 11:14:55','2026-04-07 11:14:55'),(447,69,2,'Ngorongoro Crater & Departure','Ngorongoro Conservation Area','Early morning drive to Ngorongoro Crater. Full crater game drive. Afternoon transfer to airport.','[\"Game Drive\", \"Transfer\"]','B/L',NULL,NULL,NULL,NULL,NULL,'Safari ends','2026-04-07 11:14:55','2026-04-07 11:14:55'),(448,66,1,'Arrival into Kilimanjaro/Arusha','Arusha','Arrive at Kilimanjaro International Airport or Arusha Airport. Meet and greet by your safari guide. Transfer to your hotel in Arusha for overnight stay. Rest and prepare for your safari adventure.','[\"Transfer\"]','D',NULL,'Gran Melia Arusha',NULL,NULL,NULL,'BB basis at Gran Melia','2026-04-07 11:17:50','2026-04-07 11:17:50'),(449,66,2,'Game Drive in Tarangire National Park','Tarangire National Park','Morning drive to Tarangire National Park (approx. 2 hours). Enjoy a full-day game drive in this elephant paradise. Look out for massive herds of elephants, giraffes, zebras, and predators. Ancient baobab trees dot the landscape. Evening transfer to Lake Manyara/Karatu area.','[\"Game Drive\"]','B/L/D',NULL,'Kilimamoja Lodge',NULL,NULL,NULL,'FB basis at Kilimamoja Lodge','2026-04-07 11:17:50','2026-04-07 11:17:50'),(450,66,3,'Enroute Game Drive to Serengeti','Serengeti National Park','Early morning drive to Serengeti National Park via Ngorongoro Conservation Area. Enjoy enroute game drives through the park. Check into your lodge in Central Serengeti. Afternoon game drive in search of the Big Five.','[\"Game Drive\", \"Transfer\"]','B/L/D',NULL,'Lake Magadi Lodge',NULL,NULL,NULL,'FB basis, 2 nights at Lake Magadi','2026-04-07 11:17:50','2026-04-07 11:17:50'),(451,66,4,'Full Day Game Drive in Serengeti','Serengeti National Park','Full day game drive in Serengeti National Park. Explore different regions of the park in search of the Great Migration. Picnic lunch in the bush. Evening return to lodge. The Serengeti offers unparalleled wildlife viewing year-round.','[\"Game Drive\"]','B/L/D',NULL,'Lake Magadi Lodge',NULL,NULL,NULL,'Second night in Central Serengeti','2026-04-07 11:17:50','2026-04-07 11:17:50'),(452,66,5,'Ngorongoro Crater & Maasai Boma Visit','Ngorongoro Conservation Area','Morning descent into Ngorongoro Crater for a spectacular game drive. The crater floor is home to over 25,000 large animals including the Big Five. Afternoon visit to a traditional Maasai boma for a cultural experience. Transfer to Ngorongoro/Karatu for overnight.','[\"Game Drive\", \"Cultural\"]','B/L/D',NULL,'Melia Lodge Ngorongoro',NULL,NULL,NULL,'HB basis at Melia Lodge','2026-04-07 11:17:50','2026-04-07 11:17:50'),(453,66,6,'Departure to Kilimanjaro/Arusha Airport','Arusha','Morning at leisure. After breakfast, depart for Kilimanjaro International Airport or Arusha for your onward journey. Safari ends with unforgettable memories.','[\"Transfer\"]','B',NULL,NULL,NULL,NULL,NULL,'Safari ends','2026-04-07 11:17:50','2026-04-07 11:17:50');
