INSERT INTO `safaris` VALUES (66,'Classic Tanzania Safari',NULL,'classic-tanzania-safari','Wildlife Safari',7,7,'[\"Tarangire\", \"Serengeti\", \"Ngorongoro\"]',5135,'https://images.unsplash.com/photo-1516426122078-c23e76319801?w=1200','[\"http://localhost:8000/storage/safaris/nXYehZgerrurnfqxvZGyTYzAzbsQ9DFUYUvVQJH7.jpg\", \"http://localhost:8000/storage/safaris/E3ymzSq3JPRJzeTCL9A8JEtht4vKu2a67z3oWv3y.jpg\", \"http://localhost:8000/storage/safaris/QnxZSHPbJ5MDkbUJKFFENJUxCWj7eyZI52tgCAgK.jpg\"]',NULL,NULL,'[\"Great Migration in Serengeti\", \"Ngorongoro Crater game drives\", \"Tarangire elephant herds\", \"Big Five wildlife encounters\", \"Maasai cultural boma visit\", \"Sunrise over the savanna\"]','[\"Accommodation as specified in the itinerary\", \"All meals during safari (B=Breakfast, L=Lunch, D=Dinner)\", \"Professional English-speaking driver/guide\", \"Private 4WD safari vehicle with pop-up roof\", \"All national park fees and conservation fees\", \"AMREF Flying Doctor Evacuation Insurance\", \"All airport transfers in Kilimanjaro/Arusha\", \"Bottled drinking water throughout the safari\"]','[\"International flights\", \"Visa fees\", \"Travel insurance\", \"Personal gratuities and tips (guide $35/day)\", \"Alcoholic beverages and premium drinks\", \"Optional activities not mentioned in itinerary\", \"Personal expenses (phone calls, laundry, etc.)\"]','[{\"label\": \"1 person\", \"price\": 6980}, {\"label\": \"2 persons\", \"price\": 5135}, {\"label\": \"3 persons\", \"price\": 4965}, {\"label\": \"4 persons\", \"price\": 4555}, {\"label\": \"5 persons\", \"price\": 4560}, {\"label\": \"6 persons\", \"price\": 4350}]',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'Max 6 guests','Easy','[\"Jan\",\"Feb\",\"Mar\",\"Jun\",\"Jul\",\"Aug\",\"Sep\",\"Oct\",\"Nov\",\"Dec\"]','[\"Jan\", \"Feb\", \"Mar\", \"Jun\", \"Jul\", \"Aug\", \"Sep\", \"Oct\", \"Nov\", \"Dec\"]',6,'Explore the Northern Circuit: Tarangire, Serengeti, and Ngorongoro Crater in 7 days of unforgettable wildlife adventure.','Experience the best of Tanzania\'s wildlife on this classic 7-day safari through Tarangire National Park, Serengeti National Park, and Ngorongoro Conservation Area. Witness the Great Migration, explore the world-famous Ngorongoro Crater, and marvel at Tarangire\'s elephant herds and ancient baobab trees. This safari offers premium, superior, and standard accommodation options to suit every traveler\'s preferences and budget.',NULL,'published',1,0,'2026-04-03 19:51:45','2026-04-07 11:17:50'),(67,'Serengeti & Ngorongoro Express',NULL,'serengeti-ngorongoro-express','Wildlife Safari',5,5,'[\"Serengeti\", \"Ngorongoro\"]',4255,'https://images.unsplash.com/photo-1547471080-7cc2caa01a7e?w=1200','[\"http://localhost:8000/storage/safaris/J6UlGDhNeCvT5375PchInUOgS7LV3skyDoFmnSPv.jpg\", \"http://localhost:8000/storage/safaris/h4lKyETv9hWtNjRFyMv3SfF77hf6YNz66ISqKf7D.jpg\", \"http://localhost:8000/storage/safaris/UqjhrBnNKuLzzWj7YrUKlVj3stlZw3xNMHDPvjng.jpg\"]',NULL,NULL,'[\"Serengeti game drives\", \"Ngorongoro Crater descent\", \"Masai boma cultural visit\", \"Big Five in two ecosystems\"]','[\"Accommodation as specified in the itinerary\", \"All meals during safari (B=Breakfast, L=Lunch, D=Dinner)\", \"Professional English-speaking driver/guide\", \"Private 4WD safari vehicle with pop-up roof\", \"All national park fees and conservation fees\", \"AMREF Flying Doctor Evacuation Insurance\", \"All airport transfers in Kilimanjaro/Arusha\", \"Bottled drinking water throughout the safari\"]','[\"International flights\", \"Visa fees\", \"Travel insurance\", \"Personal gratuities and tips (guide $35/day)\", \"Alcoholic beverages and premium drinks\", \"Optional activities not mentioned in itinerary\", \"Personal expenses (phone calls, laundry, etc.)\"]','[{\"label\": \"1 person\", \"price\": 5550}, {\"label\": \"2 persons\", \"price\": 4255}, {\"label\": \"3 persons\", \"price\": 4080}, {\"label\": \"4 persons\", \"price\": 3805}, {\"label\": \"5 persons\", \"price\": 3785}, {\"label\": \"6 persons\", \"price\": 3650}]',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'Max 6 guests','Easy','[\"Jan\",\"Feb\",\"Mar\",\"Jun\",\"Jul\",\"Aug\",\"Sep\",\"Oct\",\"Nov\",\"Dec\"]','[\"Jan\", \"Feb\", \"Mar\", \"Jun\", \"Jul\", \"Aug\", \"Sep\", \"Oct\", \"Nov\", \"Dec\"]',6,'A concentrated 5-day safari through Serengeti and Ngorongoro Crater with premium accommodations.','This 5-day express safari takes you to two of Tanzania\'s most iconic destinations: the endless plains of the Serengeti and the natural wonder of Ngorongoro Crater. Perfect for travelers with limited time who want maximum wildlife encounters. Choose from Premium, Superior, or Standard accommodation tiers.',NULL,'published',0,0,'2026-04-03 19:51:45','2026-04-07 11:11:52'),(68,'Tanzania Sampler Safari',NULL,'tanzania-sampler-safari','Wildlife Safari',3,3,'[\"Arusha\", \"Tarangire\", \"Ngorongoro\"]',1590,'https://images.unsplash.com/photo-1534177616064-26c1014be040?w=1200','[\"http://localhost:8000/storage/safaris/UvyAqg6V8Aqj2l2TuH3WNwNvWjkvQ3csAigVPPNQ.jpg\", \"http://localhost:8000/storage/safaris/HhIbVOpuOpkFIAK67buVJmEacEVl9pvJkcaraJzn.jpg\", \"http://localhost:8000/storage/safaris/uMfHF45kcoQMRk1UCeZ2hXmWuVdR8gDwpZEh5Htw.jpg\"]',NULL,NULL,'[\"Arusha National Park day trip\", \"Tarangire elephant herds\", \"Ngorongoro Crater game drive\"]','[\"Accommodation as specified in the itinerary\", \"All meals during safari (B=Breakfast, L=Lunch, D=Dinner)\", \"Professional English-speaking driver/guide\", \"Private 4WD safari vehicle with pop-up roof\", \"All national park fees and conservation fees\", \"AMREF Flying Doctor Evacuation Insurance\", \"All airport transfers in Kilimanjaro/Arusha\", \"Bottled drinking water throughout the safari\"]','[\"International flights\", \"Visa fees\", \"Travel insurance\", \"Personal gratuities and tips (guide $35/day)\", \"Alcoholic beverages and premium drinks\", \"Optional activities not mentioned in itinerary\", \"Personal expenses (phone calls, laundry, etc.)\"]','[{\"label\": \"1 person\", \"price\": 2520}, {\"label\": \"2 persons\", \"price\": 1590}, {\"label\": \"3 persons\", \"price\": 1425}, {\"label\": \"4 persons\", \"price\": 1245}, {\"label\": \"5 persons\", \"price\": 1265}, {\"label\": \"6 persons\", \"price\": 1120}]',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'Max 6 guests','Easy','[\"Jan\",\"Feb\",\"Mar\",\"Jun\",\"Jul\",\"Aug\",\"Sep\",\"Oct\",\"Nov\",\"Dec\"]','[\"Jan\", \"Feb\", \"Mar\", \"Jun\", \"Jul\", \"Aug\", \"Sep\", \"Oct\", \"Nov\", \"Dec\"]',6,'A quick 3-day introduction to Tanzania\'s Northern Circuit highlights.','Perfect for travelers with limited time, this 3-day sampler safari covers Arusha National Park, Tarangire National Park, and Ngorongoro Crater. Experience diverse wildlife, stunning landscapes, and the rich culture of Tanzania in a compact itinerary.',NULL,'published',0,0,'2026-04-03 19:51:45','2026-04-07 11:13:11'),(69,'Tarangire & Ngorongoro Quick Escape',NULL,'tarangire-ngorongoro-quick-escape','Wildlife Safari',2,2,'[\"Tarangire\", \"Ngorongoro\"]',1550,'https://images.unsplash.com/photo-1518709766631-a6a7f45921c3?w=1200','[\"http://localhost:8000/storage/safaris/upidlOrTpIiPcLxt802XmfBumXCnOzpIsp4syOMQ.jpg\", \"http://localhost:8000/storage/safaris/E1DTNQN49mAFCYIHrV3ttplNqPqlHcmtyrNSJAip.jpg\", \"http://localhost:8000/storage/safaris/Ejr7ZnSMcuwuc0ytk3Ond6ne4dSepSyrtN5UWgtd.jpg\"]',NULL,NULL,'[\"Tarangire game drive\", \"Ngorongoro Crater exploration\", \"Quick but comprehensive wildlife experience\"]','[\"Accommodation as specified in the itinerary\", \"All meals during safari (B=Breakfast, L=Lunch, D=Dinner)\", \"Professional English-speaking driver/guide\", \"Private 4WD safari vehicle with pop-up roof\", \"All national park fees and conservation fees\", \"AMREF Flying Doctor Evacuation Insurance\", \"All airport transfers in Kilimanjaro/Arusha\", \"Bottled drinking water throughout the safari\"]','[\"International flights\", \"Visa fees\", \"Travel insurance\", \"Personal gratuities and tips (guide $35/day)\", \"Alcoholic beverages and premium drinks\", \"Optional activities not mentioned in itinerary\", \"Personal expenses (phone calls, laundry, etc.)\"]','[{\"label\": \"1 person\", \"price\": 1970}, {\"label\": \"2 persons\", \"price\": 1550}, {\"label\": \"3 persons\", \"price\": 1215}, {\"label\": \"4 persons\", \"price\": 1200}, {\"label\": \"5 persons\", \"price\": 1065}, {\"label\": \"6 persons\", \"price\": 1075}]',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'Max 6 guests','Easy','[\"Jan\",\"Feb\",\"Mar\",\"Jun\",\"Jul\",\"Aug\",\"Sep\",\"Oct\",\"Nov\",\"Dec\"]','[\"Jan\", \"Feb\", \"Mar\", \"Jun\", \"Jul\", \"Aug\", \"Sep\", \"Oct\", \"Nov\", \"Dec\"]',6,'A whirlwind 2-day safari combining Tarangire and Ngorongoro Crater.','Short on time but want the full safari experience? This 2-day escape covers Tarangire National Park and the Ngorongoro Crater. Perfect as an add-on to a beach holiday or business trip to Dar es Salaam.',NULL,'published',0,0,'2026-04-03 19:51:45','2026-04-07 11:14:55'),(70,'Northern Serengeti Explorer',NULL,'northern-serengeti-explorer','Wildlife Safari',7,7,'[\"Serengeti\", \"Ngorongoro\"]',12305,'https://images.unsplash.com/photo-1631646109206-4b5616964f84?w=1200','[\"http://localhost:8000/storage/safaris/wWKdzbO7h3ZmcP13EoZa1hmA7UeWI3OAMbJmDbPP.jpg\", \"http://localhost:8000/storage/safaris/g3ZloZQ9hjk3c0xNpooe0Cwa5RLkFX5ZcPqMeYdq.jpg\", \"http://localhost:8000/storage/safaris/mtFzoD3hRyEOevIBJw8P2ml5zhtgY3wRlSR6Yq2A.jpg\"]',NULL,NULL,'[\"Northern Serengeti wilderness\", \"Mara River crossing point\", \"3 nights in North Serengeti\", \"Big Five in multiple ecosystems\", \"Ngorongoro Crater finale\"]','[\"Accommodation as specified in the itinerary\", \"All meals during safari (B=Breakfast, L=Lunch, D=Dinner)\", \"Professional English-speaking driver/guide\", \"Private 4WD safari vehicle with pop-up roof\", \"All national park fees and conservation fees\", \"AMREF Flying Doctor Evacuation Insurance\", \"All airport transfers in Kilimanjaro/Arusha\", \"Bottled drinking water throughout the safari\"]','[\"International flights\", \"Visa fees\", \"Travel insurance\", \"Personal gratuities and tips (guide $35/day)\", \"Alcoholic beverages and premium drinks\", \"Optional activities not mentioned in itinerary\", \"Personal expenses (phone calls, laundry, etc.)\", \"International flights to Mwanza\"]','[{\"label\": \"1 person\", \"price\": 14210}, {\"label\": \"2 persons\", \"price\": 12305}, {\"label\": \"3 persons\", \"price\": 12095}, {\"label\": \"4 persons\", \"price\": 11680}, {\"label\": \"5 persons\", \"price\": 11675}, {\"label\": \"6 persons\", \"price\": 11460}]',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'Max 6 guests','Moderate','[\"Jan\",\"Feb\",\"Mar\",\"Jun\",\"Jul\",\"Aug\",\"Sep\",\"Oct\",\"Nov\",\"Dec\"]','[\"Jan\", \"Feb\", \"Mar\", \"Jun\", \"Jul\", \"Aug\", \"Sep\", \"Oct\", \"Nov\", \"Dec\"]',6,'Explore the remote Northern Serengeti with 3 nights in this pristine wilderness, plus Ngorongoro Crater.','This unique 7-day safari starts from Mwanza Airport and takes you deep into Northern Serengeti, one of the most remote and wildlife-rich areas of the park. Spend 3 nights in the north, then move to Central Serengeti for 2 more nights, finishing with Ngorongoro Crater. Perfect for travelers seeking exclusivity and the Mara River crossing area.',NULL,'published',1,0,'2026-04-03 19:51:45','2026-04-07 11:00:07'),(71,'Fly-In Serengeti Safari',NULL,'fly-in-serengeti-safari','Wildlife Safari',4,4,'[\"Serengeti\"]',5585,'https://images.unsplash.com/photo-1547471080-7cc2caa01a7e?w=1200','[\"http://localhost:8000/storage/safaris/Mn5mzE6LoiGJt62QFQMUqrV0HADvntfX4ehmCwvZ.jpg\", \"http://localhost:8000/storage/safaris/TmSBGzrDKAalxL7fHQJSnMeKjvmsbm7UUPTTPEb2.jpg\", \"http://localhost:8000/storage/safaris/JJGx23Zk7Vq0Q5KaNedP36ZdyC78ABRxCoLia5Gc.jpg\"]',NULL,NULL,'[\"Fly directly into Serengeti\", \"3 full days of game drives\", \"Central Serengeti wildlife\", \"Premium tented camp experience\"]','[\"Accommodation as specified in the itinerary\", \"All meals during safari (B=Breakfast, L=Lunch, D=Dinner)\", \"Professional English-speaking driver/guide\", \"Private 4WD safari vehicle with pop-up roof\", \"All national park fees and conservation fees\", \"AMREF Flying Doctor Evacuation Insurance\", \"All airport transfers in Kilimanjaro/Arusha\", \"Bottled drinking water throughout the safari\", \"Scheduled domestic flights to/from Serengeti (on select tiers)\"]','[\"International flights\", \"Visa fees\", \"Travel insurance\", \"Personal gratuities and tips (guide $35/day)\", \"Alcoholic beverages and premium drinks\", \"Optional activities not mentioned in itinerary\", \"Personal expenses (phone calls, laundry, etc.)\", \"International and domestic airfares\", \"Zanzibar Infrastructure Tax $5/person/day\"]','[{\"label\": \"1 person\", \"price\": 6620}, {\"label\": \"2 persons\", \"price\": 5585}, {\"label\": \"3 persons\", \"price\": 5240}, {\"label\": \"4 persons\", \"price\": 5065}, {\"label\": \"5 persons\", \"price\": 4960}, {\"label\": \"6 persons\", \"price\": 4890}]',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'Max 6 guests','Easy','[\"Jan\",\"Feb\",\"Mar\",\"Jun\",\"Jul\",\"Aug\",\"Sep\",\"Oct\",\"Nov\",\"Dec\"]','[\"Jan\", \"Feb\", \"Mar\", \"Jun\", \"Jul\", \"Aug\", \"Sep\", \"Oct\", \"Nov\", \"Dec\"]',6,'Fly directly into Serengeti for 3 nights of immersive safari experience.','Skip the long drives and fly directly into the heart of Serengeti. This 4-day fly-in safari maximizes your time in the park with 3 full days of game drives. Stay at premium camps in Central Serengeti. Note: Domestic flights not included in package price.',NULL,'published',0,0,'2026-04-03 19:51:45','2026-04-07 11:04:00'),(72,'Safari & Zanzibar Beach Holiday',NULL,'safari-zanzibar-beach-holiday','Wildlife Safari',14,14,'[\"Arusha\", \"Tarangire\", \"Serengeti\", \"Ngorongoro\", \"Zanzibar\"]',9125,'https://images.unsplash.com/photo-1516426122078-c23e76319801?w=1200','[\"http://localhost:8000/storage/safaris/VF2yVCCB6B8EyjIfXMbYPXDjfErsHb4Bb9uV4wfZ.jpg\", \"http://localhost:8000/storage/safaris/4KcC0FcgkgIKVUojGWS2b4b3JksqxyGmksD8XqxI.jpg\", \"http://localhost:8000/storage/safaris/wd2R7hmeBotkdCVht7M1cAQF2dX08QmzDfo66loc.jpg\"]',NULL,NULL,'[\"Full Northern Circuit safari\", \"Tarangire, Serengeti, Ngorongoro\", \"7 nights Zanzibar beach resort\", \"Bush and beach combination\", \"Day trip to Kilimanjaro West\"]','[\"Accommodation as specified in the itinerary\", \"All meals during safari (B=Breakfast, L=Lunch, D=Dinner)\", \"Professional English-speaking driver/guide\", \"Private 4WD safari vehicle with pop-up roof\", \"All national park fees and conservation fees\", \"AMREF Flying Doctor Evacuation Insurance\", \"All airport transfers in Kilimanjaro/Arusha\", \"Bottled drinking water throughout the safari\", \"7 nights Zanzibar beach resort (All Inclusive)\", \"Domestic flight Arusha to Zanzibar\", \"Zanzibar airport transfers\"]','[\"International flights\", \"Visa fees\", \"Travel insurance\", \"Personal gratuities and tips (guide $35/day)\", \"Alcoholic beverages and premium drinks\", \"Optional activities not mentioned in itinerary\", \"Personal expenses (phone calls, laundry, etc.)\", \"International flights\", \"Zanzibar Infrastructure Tax $5/person/day\", \"Zanzibar Insurance fee $44/person\"]','[{\"label\": \"1 person\", \"price\": 12765}, {\"label\": \"2 persons\", \"price\": 9125}, {\"label\": \"3 persons\", \"price\": 9410}, {\"label\": \"4 persons\", \"price\": 8515}, {\"label\": \"5 persons\", \"price\": 8730}, {\"label\": \"6 persons\", \"price\": 8300}]',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'Max 6 guests','Moderate','[\"Jan\",\"Feb\",\"Mar\",\"Jun\",\"Jul\",\"Aug\",\"Sep\",\"Oct\",\"Nov\",\"Dec\"]','[\"Jan\", \"Feb\", \"Mar\", \"Jun\", \"Jul\", \"Aug\", \"Sep\", \"Oct\", \"Nov\", \"Dec\"]',6,'The ultimate Tanzania experience: 7-day safari plus 7 days of Zanzibar beach relaxation.','Combine the best of both worlds: wildlife adventure in Tanzania\'s premier parks followed by a week of relaxation on Zanzibar\'s pristine beaches. This 14-day package includes a full Northern Circuit safari and 7 nights at a Zanzibar beach resort. The perfect bush-and-beach holiday.',NULL,'published',1,0,'2026-04-03 19:51:45','2026-04-07 11:01:51'),(73,'Selous (Nyerere) Fly-In Safari',NULL,'selous-nyerere-fly-in-safari','Southern Circuit',4,4,'[\"Selous\", \"Nyerere\"]',2334,'https://images.unsplash.com/photo-1518709766631-a6a7f45921c3?w=1200','[\"http://localhost:8000/storage/safaris/SC1OjV28TBjlDpRQlUmSUOLZ1tUhHOb5WKUotTyI.jpg\", \"http://localhost:8000/storage/safaris/fBI38feaxRpldFs1OiCSplzGt0WrckGFMTZ7xbHN.jpg\", \"http://localhost:8000/storage/safaris/3jqqkO7bfO3wfhP2oMRqJz18eBCn2T2LGPvjdnxR.jpg\"]',NULL,NULL,'[\"Selous (Nyerere) Game Reserve\", \"African wild dog sightings\", \"Bush walks with guides\", \"Boat safari on Rufiji River\", \"Serena Mivumo River Camp\"]','[\"Full board accommodation at Serena Mivumo River Camp\", \"Game drives in open safari vehicle\", \"All park fees and concession fees\", \"English-speaking driver guide\", \"Return transfers to/from Dar es Salaam airport\", \"Bush walks with experienced guides\"]','[\"International flights\", \"Visa fees\", \"Travel insurance\", \"Personal gratuities and tips (guide $35/day)\", \"Alcoholic beverages and premium drinks\", \"Optional activities not mentioned in itinerary\", \"Personal expenses (phone calls, laundry, etc.)\", \"Domestic flights from Dar es Salaam\", \"Boat excursion fees\"]','[{\"label\": \"1 person\", \"price\": 2334}, {\"label\": \"2 persons\", \"price\": 2334}]',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'Max 6 guests','Moderate','[\"Jun\",\"Jul\",\"Aug\",\"Sep\",\"Oct\",\"Nov\",\"Dec\",\"Jan\",\"Feb\",\"Mar\"]','[\"Jun\", \"Jul\", \"Aug\", \"Sep\", \"Oct\", \"Nov\", \"Dec\", \"Jan\", \"Feb\", \"Mar\"]',6,'Explore the remote Selous (Nyerere) Game Reserve with a 4-day fly-in safari.','Selous Game Reserve (now Nyerere National Park) is one of Africa\'s largest and least-visited wildlife areas. This 4-day fly-in safari takes you to Serena Mivumo River Camp in the heart of Selous. Experience game drives, bush walks, and boat excursions. Note: Closed during April & May (rainy season).',NULL,'published',0,0,'2026-04-03 19:51:45','2026-04-07 11:10:12'),(74,'Ruaha Fly-In Safari with Balloon Option',NULL,'ruaha-fly-in-safari-balloon','Southern Circuit',4,4,'[\"Ruaha\"]',2514,'https://images.unsplash.com/photo-1534177616064-26c1014be040?w=1200','[\"http://localhost:8000/storage/safaris/6g3ww9UfF3Dk0a3O4XdFz0Vj9aZ8WUryrZCQqPuo.jpg\", \"http://localhost:8000/storage/safaris/4POgKFz0f6BkY6iPPbkVK1cCqG8LVfFgzC8k2rX3.jpg\", \"http://localhost:8000/storage/safaris/TSwmF2JGSeus3J2EJonCo0Fach5mCxgkALIe7tDB.jpg\"]',NULL,NULL,'[\"Ruaha National Park wilderness\", \"Large elephant herds\", \"Lion prides and wild dogs\", \"Optional hot air balloon safari\", \"Ruaha River Lodge\"]','[\"Full board accommodation at Ruaha River Lodge\", \"Game drives in open safari vehicle\", \"All park fees and concession fees\", \"English-speaking driver guide\", \"Return flights to and from Dar es Salaam\", \"Return transfers to/from the airstrip\", \"Balloon safari (July-October only, on select tier)\"]','[\"International flights\", \"Visa fees\", \"Travel insurance\", \"Personal gratuities and tips (guide $35/day)\", \"Alcoholic beverages and premium drinks\", \"Optional activities not mentioned in itinerary\", \"Personal expenses (phone calls, laundry, etc.)\", \"Balloon safari add-on ($520) outside of package tier\"]','[{\"label\": \"1 person\", \"price\": 2514}, {\"label\": \"2 persons\", \"price\": 2514}, {\"label\": \"1 person (with Balloon)\", \"price\": 3034}, {\"label\": \"2 persons (with Balloon)\", \"price\": 3034}]',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'Max 6 guests','Moderate','[\"Jun\",\"Jul\",\"Aug\",\"Sep\",\"Oct\"]','[\"Jun\", \"Jul\", \"Aug\", \"Sep\", \"Oct\"]',6,'Explore remote Ruaha National Park with optional hot air balloon safari.','Ruaha National Park is Tanzania\'s largest and most remote wilderness park. This 4-day fly-in safari takes you to Ruaha River Lodge for 3 nights of game drives in one of Africa\'s last great wildlife strongholds. Optional hot air balloon safari available (July-October only).',NULL,'published',0,0,'2026-04-03 19:51:45','2026-04-07 11:08:13'),(75,'Mikumi Safari with SGR Train Experience',NULL,'mikumi-sgr-train-safari','Family Safari',3,3,'[\"Mikumi\"]',948,'https://images.unsplash.com/photo-1518709766631-a6a7f45921c3?w=1200','[\"http://localhost:8000/storage/safaris/4rS9uzUBqFFGFbpiiNPLQg2wKGtN91mavOhZn5IN.jpg\", \"http://localhost:8000/storage/safaris/J7E1nGTue4nOnDx9wNKoDXNqyk28c1GQjyhiQpDc.jpg\", \"http://localhost:8000/storage/safaris/n0WM0xYi05moys1VLAAfNmWl7O5jB9KruY23UujZ.jpg\"]',NULL,NULL,'[\"SGR train ride from Dar es Salaam\", \"Mikumi National Park game drives\", \"Mkata Floodplain wildlife\", \"Hippo Pool visit\", \"Budget-friendly safari option\"]','[\"Round-trip SGR train tickets (Dar es Salaam to Morogoro)\", \"Transfers from Morogoro to Mikumi National Park\", \"2 nights accommodation at Vuma Hills (Full Board)\", \"2 game drives in Mikumi National Park\", \"Park entrance fees and concession fees\", \"Professional driver-guide\", \"Optional morning game drive or nature walk on Day 3\"]','[\"International flights\", \"Visa fees\", \"Travel insurance\", \"Personal gratuities and tips (guide $35/day)\", \"Alcoholic beverages and premium drinks\", \"Optional activities not mentioned in itinerary\", \"Personal expenses (phone calls, laundry, etc.)\", \"Personal expenses on train\"]','[{\"label\": \"1 person (High Season)\", \"price\": 993}, {\"label\": \"2 persons (High Season)\", \"price\": 948}, {\"label\": \"1 person (Low Season)\", \"price\": 948}, {\"label\": \"2 persons (Low Season)\", \"price\": 903}]',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'Max 6 guests','Easy','[\"Jun\",\"Jul\",\"Aug\",\"Sep\",\"Oct\",\"Dec\",\"Jan\"]','[\"Jun\", \"Jul\", \"Aug\", \"Sep\", \"Oct\", \"Dec\", \"Jan\"]',6,'Combine Tanzania\'s modern SGR train with a Mikumi National Park safari.','A unique safari experience combining Tanzania\'s new Standard Gauge Railway (SGR) train with a Mikumi National Park safari. Travel from Dar es Salaam to Morogoro by train, then drive to Mikumi for 2 nights of game drives. Perfect for families and budget-conscious travelers.',NULL,'published',0,0,'2026-04-03 19:51:45','2026-04-07 11:06:22');
