INSERT INTO `team_members` VALUES (1,'Joseph Makacha','Senior Guide','18 years','[\"English\", \"Swahili\", \"German\"]','[\"Serengeti\", \"Ngorongoro\", \"Photography\"]',1,NULL,'Joseph has been guiding in the Serengeti since 2008. He can identify over 400 bird species by call and knows individual lion pride histories spanning three generations. His photography instincts make him the first choice for photography safari clients.','2026-04-03 19:51:46','2026-04-03 19:51:46'),(3,'Emmanuel Mollel','Kilimanjaro Specialist','15 years','[\"English\", \"Swahili\"]','[\"Kilimanjaro\", \"Lemosho\", \"Machame\"]',1,NULL,'Emmanuel has summited Kilimanjaro over 200 times via every route. His calm leadership on summit night has guided hundreds of clients to Uhuru Peak. He is certified in high-altitude medicine.','2026-04-03 19:51:46','2026-04-03 19:51:46'),(4,'Grace Njau','Operations Manager','10 years','[\"English\", \"Swahili\"]','[\"Operations\", \"Logistics\"]',1,NULL,'Grace ensures every safari runs flawlessly behind the scenes. From lodge confirmations to vehicle maintenance schedules, she is the operational backbone of Ronjoo Safaris.','2026-04-03 19:51:46','2026-04-03 19:51:46'),(5,'Peter Swai','Guide','8 years','[\"English\", \"Swahili\", \"Italian\"]','[\"Southern Circuit\", \"Walking Safaris\"]',1,NULL,'Peter specializes in the remote Southern Circuit, Ruaha and Nyerere. His walking safari skills are exceptional, trained by some of the finest walking guides in East Africa.','2026-04-03 19:51:46','2026-04-03 19:51:46');
