INSERT INTO `travel_guides` VALUES (29,'safari-packing-guide','Safari Packing Guide: What to Bring on Your Tanzanian Adventure','Before You Go','checklist',NULL,'8 min','2026-03-01',NULL,1,'[\"Clothing Essentials\", \"Health & Medications\", \"Documents & Money\", \"Photography Gear\", \"Miscellaneous\"]','[{\"text\": \"The Essential Safari Packing List\", \"type\": \"paragraph\"}, {\"text\": \"Packing for a Tanzanian safari requires careful consideration. The climate varies from cool mornings (10–15°C) to hot afternoons (30°C+), and luggage restrictions on light aircraft flights limit you to 15kg in soft-sided bags.\", \"type\": \"paragraph\"}, {\"text\": \"Clothing\", \"type\": \"paragraph\"}, {\"text\": \"Stick to neutral colors (khaki, olive, beige). Avoid blue and black (attract tsetse flies) and white (shows dust instantly).\", \"type\": \"paragraph\"}, {\"text\": \"Health &amp; Medications\", \"type\": \"paragraph\"}, {\"text\": \"Malaria prophylaxis is essential. Consult your doctor 4–6 weeks before travel.\", \"type\": \"paragraph\"}, {\"text\": \"Documents\", \"type\": \"paragraph\"}, {\"text\": \"Photography &amp; Electronics\", \"type\": \"paragraph\"}, {\"text\": \"Miscellaneous Essentials\", \"type\": \"paragraph\"}, {\"text\": \"Final tip: Pack everything in a soft-sided duffel bag (no hard suitcases). Light aircraft flights have a strict 15kg luggage limit.\", \"type\": \"paragraph\"}, {\"text\": \"Lightweight rain jacket (if traveling Nov–May)\", \"type\": \"paragraph\"}, {\"text\": \"Malaria prophylaxis (consult your doctor 4–6 weeks before)\", \"type\": \"paragraph\"}, {\"text\": \"Broad-spectrum sunscreen (SPF 50+)\", \"type\": \"paragraph\"}, {\"text\": \"Insect repellent with DEET (40%+)\", \"type\": \"paragraph\"}, {\"text\": \"Personal prescription medications (in original containers)\", \"type\": \"paragraph\"}, {\"text\": \"Basic first-aid kit (bandages, antiseptic, pain relievers)\", \"type\": \"paragraph\"}, {\"text\": \"Hand sanitizer\", \"type\": \"paragraph\"}, {\"text\": \"Anti-diarrheal medication (Imodium)\", \"type\": \"paragraph\"}, {\"text\": \"Rehydration salts\", \"type\": \"paragraph\"}, {\"text\": \"Valid passport (6+ months validity)\", \"type\": \"paragraph\"}, {\"text\": \"Tanzania eVisa (printed copy)\", \"type\": \"paragraph\"}, {\"text\": \"Travel insurance documents (including evacuation cover)\", \"type\": \"paragraph\"}, {\"text\": \"Vaccination certificates (Yellow Fever if required)\", \"type\": \"paragraph\"}, {\"text\": \"Flight itineraries and safari booking confirmations\", \"type\": \"paragraph\"}, {\"text\": \"Credit/debit cards (Visa is most widely accepted)\", \"type\": \"paragraph\"}, {\"text\": \"USD cash for tips ($1 bills are useful)\", \"type\": \"paragraph\"}, {\"text\": \"Photocopies of all important documents\", \"type\": \"paragraph\"}, {\"text\": \"DSLR/mirrorless camera with telephoto lens (100–400mm minimum)\", \"type\": \"paragraph\"}, {\"text\": \"Extra memory cards and batteries\", \"type\": \"paragraph\"}, {\"text\": \"Bean bag for vehicle window stabilization\", \"type\": \"paragraph\"}, {\"text\": \"Binoculars (8x42 or 10x42 recommended)\", \"type\": \"paragraph\"}, {\"text\": \"Universal power adapter (UK-style 3-pin plugs)\", \"type\": \"paragraph\"}, {\"text\": \"Portable power bank\", \"type\": \"paragraph\"}, {\"text\": \"Headlamp with red-light mode\", \"type\": \"paragraph\"}, {\"text\": \"Reusable water bottle\", \"type\": \"paragraph\"}, {\"text\": \"Sunglasses with UV protection\", \"type\": \"paragraph\"}, {\"text\": \"Quick-dry microfiber towel\", \"type\": \"paragraph\"}, {\"text\": \"Ziplock bags (for protecting electronics from dust)\", \"type\": \"paragraph\"}, {\"text\": \"Small daypack for game drives\", \"type\": \"paragraph\"}, {\"text\": \"Lightweight, breathable shirts (long-sleeve for sun protection)\", \"type\": \"paragraph\"}, {\"text\": \"Shorts or convertible pants\", \"type\": \"paragraph\"}, {\"text\": \"Fleece or warm jacket for early mornings\", \"type\": \"paragraph\"}, {\"text\": \"Wide-brimmed hat with chin strap\", \"type\": \"paragraph\"}, {\"text\": \"Comfortable, closed-toe walking shoes\", \"type\": \"paragraph\"}, {\"text\": \"Sandals for lodge evenings\", \"type\": \"paragraph\"}, {\"text\": \"Undergarments and socks (quick-dry material)\", \"type\": \"paragraph\"}, {\"text\": \"Swimwear (many lodges have pools)\", \"type\": \"paragraph\"}, {\"text\": \"Lightweight, breathable shirts (long-sleeve for sun protection)\", \"type\": \"paragraph\"}, {\"text\": \"Shorts or convertible pants\", \"type\": \"paragraph\"}, {\"text\": \"Fleece or warm jacket for early mornings\", \"type\": \"paragraph\"}, {\"text\": \"Wide-brimmed hat with chin strap\", \"type\": \"paragraph\"}, {\"text\": \"Comfortable, closed-toe walking shoes\", \"type\": \"paragraph\"}, {\"text\": \"Sandals for lodge evenings\", \"type\": \"paragraph\"}, {\"text\": \"Undergarments and socks (quick-dry material)\", \"type\": \"paragraph\"}, {\"text\": \"Swimwear (many lodges have pools)\", \"type\": \"paragraph\"}, {\"text\": \"Lightweight, breathable shirts (long-sleeve for sun protection)\", \"type\": \"paragraph\"}, {\"text\": \"Shorts or convertible pants\", \"type\": \"paragraph\"}, {\"text\": \"Fleece or warm jacket for early mornings\", \"type\": \"paragraph\"}, {\"text\": \"Wide-brimmed hat with chin strap\", \"type\": \"paragraph\"}, {\"text\": \"Comfortable, closed-toe walking shoes\", \"type\": \"paragraph\"}, {\"text\": \"Sandals for lodge evenings\", \"type\": \"paragraph\"}, {\"text\": \"Undergarments and socks (quick-dry material)\", \"type\": \"paragraph\"}, {\"text\": \"Swimwear (many lodges have pools)\", \"type\": \"paragraph\"}, {\"text\": \"Lightweight rain jacket (if traveling Nov–May)\", \"type\": \"paragraph\"}, {\"text\": \"Malaria prophylaxis (consult your doctor 4–6 weeks before)\", \"type\": \"paragraph\"}, {\"text\": \"Broad-spectrum sunscreen (SPF 50+)\", \"type\": \"paragraph\"}, {\"text\": \"Insect repellent with DEET (40%+)\", \"type\": \"paragraph\"}, {\"text\": \"Personal prescription medications (in original containers)\", \"type\": \"paragraph\"}, {\"text\": \"Basic first-aid kit (bandages, antiseptic, pain relievers)\", \"type\": \"paragraph\"}, {\"text\": \"Hand sanitizer\", \"type\": \"paragraph\"}, {\"text\": \"Anti-diarrheal medication (Imodium)\", \"type\": \"paragraph\"}, {\"text\": \"Rehydration salts\", \"type\": \"paragraph\"}, {\"text\": \"Valid passport (6+ months validity)\", \"type\": \"paragraph\"}, {\"text\": \"Tanzania eVisa (printed copy)\", \"type\": \"paragraph\"}, {\"text\": \"Travel insurance documents (including evacuation cover)\", \"type\": \"paragraph\"}, {\"text\": \"Vaccination certificates (Yellow Fever if required)\", \"type\": \"paragraph\"}, {\"text\": \"Flight itineraries and safari booking confirmations\", \"type\": \"paragraph\"}, {\"text\": \"Credit/debit cards (Visa is most widely accepted)\", \"type\": \"paragraph\"}, {\"text\": \"USD cash for tips ($1 bills are useful)\", \"type\": \"paragraph\"}, {\"text\": \"Photocopies of all important documents\", \"type\": \"paragraph\"}, {\"text\": \"DSLR/mirrorless camera with telephoto lens (100–400mm minimum)\", \"type\": \"paragraph\"}, {\"text\": \"Extra memory cards and batteries\", \"type\": \"paragraph\"}, {\"text\": \"Bean bag for vehicle window stabilization\", \"type\": \"paragraph\"}, {\"text\": \"Binoculars (8x42 or 10x42 recommended)\", \"type\": \"paragraph\"}, {\"text\": \"Universal power adapter (UK-style 3-pin plugs)\", \"type\": \"paragraph\"}, {\"text\": \"Portable power bank\", \"type\": \"paragraph\"}, {\"text\": \"Headlamp with red-light mode\", \"type\": \"paragraph\"}, {\"text\": \"Reusable water bottle\", \"type\": \"paragraph\"}, {\"text\": \"Sunglasses with UV protection\", \"type\": \"paragraph\"}, {\"text\": \"Quick-dry microfiber towel\", \"type\": \"paragraph\"}, {\"text\": \"Ziplock bags (for protecting electronics from dust)\", \"type\": \"paragraph\"}, {\"text\": \"Small daypack for game drives\", \"type\": \"paragraph\"}]',NULL,'published','Complete packing checklist for your Tanzania safari. Clothing, gear, documents, and health essentials.','[\"Lightweight, breathable shirts (long-sleeve for sun protection)\", \"Shorts or convertible pants\", \"Fleece or warm jacket for early mornings\", \"Wide-brimmed hat with chin strap\", \"Comfortable, closed-toe walking shoes\", \"Sandals for lodge evenings\", \"Undergarments and socks (quick-dry material)\", \"Swimwear (many lodges have pools)\", \"Lightweight rain jacket (if traveling Nov–May)\", \"Malaria prophylaxis (consult your doctor 4–6 weeks before)\", \"Broad-spectrum sunscreen (SPF 50+)\", \"Insect repellent with DEET (40%+)\", \"Personal prescription medications (in original containers)\", \"Basic first-aid kit (bandages, antiseptic, pain relievers)\", \"Hand sanitizer\", \"Anti-diarrheal medication (Imodium)\", \"Rehydration salts\", \"Valid passport (6+ months validity)\", \"Tanzania eVisa (printed copy)\", \"Travel insurance documents (including evacuation cover)\", \"Vaccination certificates (Yellow Fever if required)\", \"Flight itineraries and safari booking confirmations\", \"Credit/debit cards (Visa is most widely accepted)\", \"USD cash for tips ($1 bills are useful)\", \"Photocopies of all important documents\", \"DSLR/mirrorless camera with telephoto lens (100–400mm minimum)\", \"Extra memory cards and batteries\", \"Bean bag for vehicle window stabilization\", \"Binoculars (8x42 or 10x42 recommended)\", \"Universal power adapter (UK-style 3-pin plugs)\", \"Portable power bank\", \"Headlamp with red-light mode\", \"Reusable water bottle\", \"Sunglasses with UV protection\", \"Quick-dry microfiber towel\", \"Ziplock bags (for protecting electronics from dust)\", \"Small daypack for game drives\"]','Safari Packing Guide: Complete Checklist for Tanzania','Complete safari packing checklist for Tanzania. Clothing, gear, documents, health essentials, and photography equipment.','2026-04-03 19:51:46','2026-04-04 04:11:27'),(30,'best-time-to-visit-tanzania','Best Time to Visit Tanzania: Month-by-Month Safari Calendar','Before You Go','comprehensive',NULL,'12 min','2026-02-15',NULL,1,'[\"Dry vs. Green Season\", \"Monthly Wildlife Calendar\", \"Pricing & Crowds\", \"Our Recommendation\"]','[{\"body\": \"Tanzania\'s Two Seasons\", \"type\": \"heading\", \"level\": 2}, {\"body\": \"Tanzania has two main seasons: the Dry Season (June–October) and the Green Season (November–May).\", \"type\": \"text\"}, {\"body\": \"Dry Season (June–October)\", \"type\": \"heading\", \"level\": 2}, {\"body\": \"Wildlife congregates around rivers and waterholes, making sightings predictable and spectacular. Skies are clear, roads are passable, and mosquito numbers are lower.\", \"type\": \"text\"}, {\"body\": \"Peak wildlife: July–October (Great Migration river crossings). Weather: Sunny, 20–30°C. Crowds: Highest in July, August. Pricing: Premium rates (20–40% higher).\", \"type\": \"text\"}, {\"body\": \"Green Season (November–May)\", \"type\": \"heading\", \"level\": 2}, {\"body\": \"The savanna transforms into a lush, emerald paradise. Birding is at its peak, newborn animals are everywhere. Short rains (Nov–Dec) bring brief afternoon showers. Long rains (Mar–May) can make some roads impassable.\", \"type\": \"text\"}, {\"body\": \"Peak wildlife: January–March (calving season). Weather: Warm, humid, 25–35°C. Crowds: Lowest in April–May. Pricing: Significant discounts (20–50% off).\", \"type\": \"text\"}, {\"body\": \"Our Recommendation\", \"type\": \"heading\", \"level\": 2}, {\"body\": \"For Great Migration: July–October. For budget travelers: April–June. For calving season: January–February. For balance of weather and price: June or November.\", \"type\": \"text\"}]',NULL,'published','Detailed monthly breakdown of Tanzania\'s safari seasons, wildlife events, weather patterns, and pricing.',NULL,'Best Time to Visit Tanzania: Monthly Safari Calendar','When to visit Tanzania for safaris. Monthly breakdown of wildlife, weather, pricing, and crowds.','2026-04-03 19:51:46','2026-04-03 19:51:46'),(31,'health-vaccinations-tanzania','Health & Vaccinations: Essential Guide for Tanzania Travel','Before You Go','standard',NULL,'10 min','2026-01-20',NULL,1,'[\"Required Vaccinations\", \"Recommended Vaccinations\", \"Malaria Prevention\", \"Travel Insurance\", \"Food & Water Safety\"]','[{\"body\": \"Required Vaccinations\", \"type\": \"heading\", \"level\": 2}, {\"body\": \"Yellow Fever vaccination is required if arriving from a country with risk. We recommend it for all travelers for lifelong protection.\", \"type\": \"text\"}, {\"body\": \"Recommended Vaccinations\", \"type\": \"heading\", \"level\": 2}, {\"body\": \"Hepatitis A, Hepatitis B, Typhoid, Tetanus-Diphtheria (booster every 10 years), Rabies (for long stays or remote travel). Consult your travel health clinic 4–6 weeks before departure.\", \"type\": \"text\"}, {\"body\": \"Malaria Prevention\", \"type\": \"heading\", \"level\": 2}, {\"body\": \"Prophylaxis: Malarone, Doxycycline, or Mefloquine. Insect repellent with DEET 40%+. Permethrin-treated clothing. Mosquito nets provided at all lodges.\", \"type\": \"text\"}, {\"body\": \"Travel Insurance\", \"type\": \"heading\", \"level\": 2}, {\"body\": \"Must cover: Emergency medical evacuation ($500,000+), hospital treatment, repatriation, trip cancellation. AMREF Flying Doctors included in safari packages.\", \"type\": \"text\"}, {\"body\": \"Food & Water Safety\", \"type\": \"heading\", \"level\": 2}, {\"body\": \"Drink only bottled or filtered water. All lodges provide safe drinking water. Eat well-cooked food and peel fruits yourself.\", \"type\": \"text\"}]',NULL,'published','Complete health guide: required vaccinations, malaria prevention, travel insurance, and medical preparedness.',NULL,'Health & Vaccinations Guide for Tanzania Travel','Complete health guide for Tanzania: vaccinations, malaria prevention, travel insurance, and medical preparedness.','2026-04-03 19:51:46','2026-04-03 19:51:46'),(32,'money-currency-tipping-tanzania','Money, Currency & Tipping on Safari: A Complete Guide','On Safari','standard',NULL,'6 min','2026-02-10',NULL,0,'[\"Tanzanian Currency\", \"USD Requirements\", \"ATMs & Cards\", \"Tipping Guidelines\", \"Budgeting for Extras\"]','[{\"body\": \"Currency in Tanzania\", \"type\": \"heading\", \"level\": 2}, {\"body\": \"Official currency is Tanzanian Shilling (TZS). USD is widely accepted in tourism. Exchange rate: $1 USD ≈ 2,500–2,600 TZS.\", \"type\": \"text\"}, {\"body\": \"USD Requirements\", \"type\": \"heading\", \"level\": 2}, {\"body\": \"Tanzania requires USD bills printed in 2009 or later. Bills should be crisp and unmarked. Bring $1 bills for small tips, $5–$20 for larger tips and souvenirs.\", \"type\": \"text\"}, {\"body\": \"ATMs & Credit Cards\", \"type\": \"heading\", \"level\": 2}, {\"body\": \"ATMs available in Arusha and Dar es Salaam. Visa more widely accepted than Mastercard. Credit cards accepted at larger lodges but not remote camps.\", \"type\": \"text\"}, {\"body\": \"Tipping Guidelines\", \"type\": \"heading\", \"level\": 2}, {\"body\": \"Safari Guide: $35/day per vehicle (private) or $20–25/person/day (group). Camp Staff: $5–10/day (tip box). Porters: $10–15/day. Restaurant: 10% if service charge not included.\", \"type\": \"text\"}]',NULL,'published','Everything about money in Tanzania: currency, ATMs, credit cards, tipping guidelines, and budgeting.',NULL,'Money, Currency & Tipping Guide for Tanzania Safari','Complete guide to money in Tanzania: currency, ATMs, credit cards, tipping safari guides, and budgeting.','2026-04-03 19:51:46','2026-04-03 19:51:46'),(33,'swahili-phrases-safari-travelers','Essential Swahili Phrases for Safari Travelers','People & Culture','interactive',NULL,'5 min','2026-01-05',NULL,0,'[\"Greetings & Gratitude\", \"Wildlife Vocabulary\", \"Useful Phrases\", \"Cultural Notes\"]','[{\"body\": \"Essential Greetings\", \"type\": \"heading\", \"level\": 2}, {\"body\": \"Jambo! — Hello! | Habari? — How are you? | Nzuri — Good/Fine | Asante — Thank you | Asante sana — Thank you very much | Karibu — You\'re welcome | Kwaheri — Goodbye | Lala salama — Sleep well\", \"type\": \"text\"}, {\"body\": \"On Safari\", \"type\": \"heading\", \"level\": 2}, {\"body\": \"Simba! — Lion! | Chui — Leopard | Tembo — Elephant | Kifaru — Rhinoceros | Nyati — Buffalo | Twiga — Giraffe | Punda milia — Zebra | Nyoka — Snake | Ndege — Bird/Airplane\", \"type\": \"text\"}, {\"body\": \"Useful Phrases\", \"type\": \"heading\", \"level\": 2}, {\"body\": \"Ndiyo — Yes | Hapana — No | Tafadhali — Please | Pole pole — Slowly, slowly | Haraka haraka — Quickly, quickly | Hakuna matata — No worries | Safari njema — Good journey\", \"type\": \"text\"}, {\"body\": \"Cultural Tip\", \"type\": \"heading\", \"level\": 2}, {\"body\": \"In Maasai culture, the traditional greeting is \\\"Kasserian Ingera?\\\" (And how are the children?). Response: \\\"All the children are well.\\\"\", \"type\": \"text\"}]',NULL,'published','Learn essential Swahili phrases for your Tanzania safari. Greetings, wildlife vocabulary, and cultural tips.',NULL,'Essential Swahili Phrases for Safari Travelers','Learn essential Swahili phrases for your Tanzania safari. Greetings, wildlife vocabulary, and cultural tips.','2026-04-03 19:51:46','2026-04-03 19:51:46'),(34,'photography-on-safari-complete-guide','Wildlife Photography Masterclass: Complete Safari Photography Guide','Specialist Guides','comprehensive',NULL,'15 min','2026-03-05',NULL,1,'[\"Camera & Lens Selection\", \"Essential Settings\", \"Composition Techniques\", \"Ethics & Safety\", \"Post-Processing\"]','[{\"body\": \"Gear Selection\", \"type\": \"heading\", \"level\": 2}, {\"body\": \"Camera: Canon EOS R6 II, Sony A7 IV, Nikon Z8, or OM System OM-1 (2x crop factor). Lenses: 100–400mm or 150–600mm for wildlife. 24–70mm f/2.8 for landscapes. 70–200mm f/2.8 for low-light predators.\", \"type\": \"text\"}, {\"body\": \"Essential Settings\", \"type\": \"heading\", \"level\": 2}, {\"body\": \"Shutter: 1/1000s minimum for moving subjects. Aperture: f/5.6–f/8 for wildlife. ISO: Auto, max 3200 (full-frame) or 6400 (APS-C). Autofocus: AI Servo/AF-C with animal eye detection. Drive: High-speed continuous, 5–10 frame bursts.\", \"type\": \"text\"}, {\"body\": \"Composition Techniques\", \"type\": \"heading\", \"level\": 2}, {\"body\": \"Eye Level: Get down to the animal\'s eye level. Rule of Thirds: Place subject\'s eye on intersection point. Environmental Context: Include landscape to tell the story. Golden Hour: First and last 90 minutes of daylight.\", \"type\": \"text\"}, {\"body\": \"Ethics & Safety\", \"type\": \"heading\", \"level\": 2}, {\"body\": \"Never pressure your guide to approach wildlife. Minimum 20m from most wildlife, 50m from predators. No call playback—it disrupts natural behavior and is banned in many parks.\", \"type\": \"text\"}, {\"body\": \"Post-Processing\", \"type\": \"heading\", \"level\": 2}, {\"body\": \"Shoot RAW. Import to Lightroom or Capture One. Adjust exposure (+0.3 to +0.7), contrast (+10–20), highlight recovery (-30 to -50), shadow lift (+20–40). Crop to strengthen composition. Export JPEG at 85–90% for web.\", \"type\": \"text\"}]',NULL,'published','Master wildlife photography on safari. Camera settings, lens selection, composition, ethics, and post-processing.',NULL,'Wildlife Photography Masterclass: Complete Safari Guide','Master wildlife photography on safari. Camera settings, composition, ethics, and post-processing from professionals.','2026-04-03 19:51:46','2026-04-03 19:51:46'),(35,'safari-vehicles-accommodation-comparison','Safari Vehicles & Accommodation: Understanding Your Options','Planning','comparison',NULL,'10 min','2026-02-25',NULL,0,'[\"Safari Vehicle Types\", \"Accommodation Tiers\", \"What\'s Included\", \"Choosing the Right Tier\"]','[{\"body\": \"Safari Vehicles\", \"type\": \"heading\", \"level\": 2}, {\"body\": \"Standard 4x4 Land Cruiser: Toyota 70-series, pop-up roof, seats 6–7. Extended 4x4 Land Cruiser: Extended wheelbase, guaranteed window seat, enhanced suspension, charging ports. Modified Safari Van: Converted HiAce, budget option, not recommended for rough roads.\", \"type\": \"text\"}, {\"body\": \"Accommodation Tiers\", \"type\": \"heading\", \"level\": 2}, {\"body\": \"Budget Camping ($800–1,500/day): Mobile dome tents, shared facilities, campfire meals. Mid-Range Lodges ($300–600/day): En-suite bathrooms, hot water, pools, restaurant dining. Premium Tented Camps ($600–1,200/day): Luxury canvas tents, flush toilets, gourmet dining, private concessions. Ultra-Luxury ($1,200–2,500+/day): Private villas, plunge pools, spa treatments, helicopter transfers.\", \"type\": \"text\"}, {\"body\": \"What\'s Included?\", \"type\": \"heading\", \"level\": 2}, {\"body\": \"Included: accommodation, meals (FB/HB), game drives, park fees, guide, drinking water. Not included: international flights, visas, insurance, tips, premium alcohol, laundry, optional activities.\", \"type\": \"text\"}, {\"body\": \"Choosing the Right Tier\", \"type\": \"heading\", \"level\": 2}, {\"body\": \"For 3–4 days: mid-range lodges offer best value. For 7+ days: mix tiers (2 nights mid-range, 3 nights premium in Serengeti, 1 night mid-range return).\", \"type\": \"text\"}]',NULL,'published','Compare safari vehicle types, accommodation tiers, and understand what you\'re paying for at each level.',NULL,'Safari Vehicles & Accommodation: Complete Comparison Guide','Compare safari vehicles, accommodation tiers, and understand pricing. From budget camping to ultra-luxury.','2026-04-03 19:51:46','2026-04-03 19:51:46');
