INSERT INTO `wildlife` VALUES (1,'Lion','lion','Big Five','https://images.unsplash.com/photo-1614027164847-1b28cfe1df60?w=640&q=80','The crater hosts a dense population of large-maned lions who are famously unperturbed by vehicles.',NULL,NULL,'2026-04-07 08:27:20','2026-04-07 08:27:20'),(2,'Leopard','leopard','Big Five','https://images.unsplash.com/photo-1575550959106-5a7defe28b56?w=640&q=80','Masters of disguise, they are often found in the larger trees along the Tarangire River.',NULL,NULL,'2026-04-07 08:27:20','2026-04-07 08:27:20'),(3,'Cheetah','cheetah','Predator','https://images.unsplash.com/photo-1534149043227-d4677db02787?w=640&q=80','The open plains provide the perfect high-speed hunting grounds for these cats.',NULL,NULL,'2026-04-07 08:27:20','2026-04-07 08:27:20'),(4,'Elephant','elephant','Big Five','https://images.unsplash.com/photo-1557050543-4d5f4e07ef46?w=640&q=80','The park supports a healthy population of elephants that move frequently between the forest and the lake.',NULL,NULL,'2026-04-07 08:27:20','2026-04-07 08:27:20'),(5,'Black Rhino','black-rhino','Big Five','https://images.unsplash.com/photo-1598894000396-bc30e0996899?w=640&q=80','One of the few places in East Africa where black rhino can be reliably spotted in the wild.',NULL,NULL,'2026-04-07 08:27:20','2026-04-07 08:27:20'),(6,'Hippo','hippo','Herbivore','https://images.unsplash.com/photo-1534149043227-d4677db02787?w=640&q=80','The Rufiji River is home to massive pods of hippos, which are best seen from a boat safari.',NULL,NULL,'2026-04-07 08:27:20','2026-04-07 08:27:20'),(7,'Flamingo','flamingo','Bird','https://images.unsplash.com/photo-1598894000396-bc30e0996899?w=640&q=80','Thousands of flamingos gather at the Momella Lakes, creating a pink haze on the water.',NULL,NULL,'2026-04-07 08:27:20','2026-04-07 08:27:20'),(8,'African Elephant','african-elephant','Big Five','https://images.unsplash.com/photo-1549366021-9f761d450615?w=640&q=80','Tarangire has one of the highest elephant densities in Africa, herds of 300+ are common in the dry season.',NULL,NULL,'2026-04-07 08:27:20','2026-04-07 08:27:20'),(9,'Oryx','oryx','Herbivore','https://images.unsplash.com/photo-1534149043227-d4677db02787?w=640&q=80','The fringe-eared oryx is one of the more elusive and beautiful inhabitants of the drier sectors.',NULL,NULL,'2026-04-07 08:27:20','2026-04-07 08:27:20'),(10,'Giraffe','giraffe','Herbivore','https://images.unsplash.com/photo-1557050543-4d5f4e07ef46?w=640&q=80','The park has an incredibly high density of Maasai giraffes, often seen grazing against the backdrop of Mt. Meru.',NULL,NULL,'2026-04-07 08:27:20','2026-04-07 08:27:20'),(11,'Colobus Monkey','colobus-monkey','Primate','https://images.unsplash.com/photo-1555524330-9ec8058309ec?w=640&q=80','Famous for their spectacular white tails and their preference for high-canopy mountain forests.',NULL,NULL,'2026-04-07 08:27:20','2026-04-07 08:27:20'),(12,'Blue Monkey','blue-monkey','Primate','https://images.unsplash.com/photo-1546272989-40c92939c6c2?w=640&q=80','Playful and vocal inhabitants of the park\'s dense montane forests.',NULL,NULL,'2026-04-07 08:27:20','2026-04-07 08:27:20'),(13,'Buffalo','buffalo','Big Five','https://images.unsplash.com/photo-1549366021-9f761d450615?w=640&q=80','Massive herds congregate near the Mkata riverbed during the dry season.',NULL,NULL,'2026-04-07 08:27:20','2026-04-07 08:27:20'),(14,'Baboon','baboon','Primate','https://images.unsplash.com/photo-1546272989-40c92939c6c2?w=640&q=80','Manyara is home to some of the largest baboon troops seen in Africa.',NULL,NULL,'2026-04-07 08:27:20','2026-04-07 08:27:20'),(15,'Four-striped Mouse','four-striped-mouse','Herbivore','https://images.unsplash.com/photo-1535338454528-1b5a4f159e53?w=640&q=80','A resilient inhabitant of the higher alpine moorland zones.',NULL,NULL,'2026-04-07 08:27:20','2026-04-07 08:27:20'),(16,'Malachite Sunbird','malachite-sunbird','Bird','https://images.unsplash.com/photo-1516426122078-c23e76319801?w=640&q=80','Often seen feeding on the nectar of giant lobelias in the moorland zone.',NULL,NULL,'2026-04-07 08:27:20','2026-04-07 08:27:20'),(17,'Wild Dog','wild-dog','Predator','https://images.unsplash.com/photo-1575550959106-5a7defe28b56?w=640&q=80','Nyerere is one of the best places in the world to see the highly endangered and social African wild dog.',NULL,NULL,'2026-04-07 08:27:20','2026-04-07 08:27:20'),(18,'Greater Kudu','greater-kudu','Herbivore','https://images.unsplash.com/photo-1549366021-9f761d450615?w=640&q=80','The park\'s emblem, these elegant antelopes are frequently seen in the bush lands.',NULL,NULL,'2026-04-07 08:27:20','2026-04-07 08:27:20'),(19,'Crocodile','crocodile','Predator','https://images.unsplash.com/photo-1516298773066-c48f8e9a4842?w=640&q=80','Huge Nile crocodiles bask along the riverbanks and can be seen in the various lakes.',NULL,NULL,'2026-04-07 08:27:20','2026-04-07 08:27:20'),(20,'Red Colobus Monkey','red-colobus-monkey','Primate','https://images.unsplash.com/photo-1555524330-9ec8058309ec?w=640&q=80','Endemic to Zanzibar, these playful monkeys are best seen in the Jozani Chwaka Bay National Park.',NULL,NULL,'2026-04-07 08:27:20','2026-04-07 08:27:20'),(21,'Dolphin','dolphin','Marine','https://images.unsplash.com/photo-1590523277543-a94d2e4eb00b?w=640&q=80','Frequently seen in effectively protected areas like the Menai Bay Conservation Area.',NULL,NULL,'2026-04-07 08:27:20','2026-04-07 08:27:20'),(22,'Turtles','turtles','Marine','https://images.unsplash.com/photo-1586861635167-e5223aadc9fe?w=640&q=80','Green sea turtles nest on several of the archipelago\'s remote beaches and satellite islands.',NULL,NULL,'2026-04-07 08:27:20','2026-04-07 08:27:20'),(23,'Giant Aldabra Tortoise','giant-aldabra-tortoise','Marine','https://images.unsplash.com/photo-1590523277543-a94d2e4eb00b?w=640&q=80','A protected population can be visited on Prison Island, some individuals are over 150 years old.',NULL,NULL,'2026-04-07 08:27:20','2026-04-07 08:27:20'),(24,'Suni Antelope','suni-antelope','Herbivore','https://images.unsplash.com/photo-1546272989-40c92939c6c2?w=640&q=80','One of the smallest antelopes in the world, found in the island\'s dry forests and thickets.',NULL,NULL,'2026-04-07 08:27:20','2026-04-07 08:27:20'),(25,'Eland','eland','Herbivore','https://images.unsplash.com/photo-1546272989-40c92939c6c2?w=640&q=80','The largest antelope in Africa is frequently seen in the park\'s more open areas.',NULL,NULL,'2026-04-07 08:27:20','2026-04-07 08:27:20');
